B.ZS=new A.l(2000,3,18,"\ub300\ub9cc \uc815\uad8c\uad50\uccb4","\ucc9c\uc218\uc774\ubcdc\uc774 \ub300\ub9cc \ucd1d\ud1b5\uc5d0 \ub2f9\uc120\ub410\ub2e4","\uad6d\ubbfc\ub2f9\uc758 \ubc18\uc138\uae30 \uc9d1\uad8c\uc774 \ucc98\uc74c\uc73c\ub85c \ub9c9\uc744 \ub0b4\ub838\ub2e4. \uc591\uc548 \uad00\uacc4\uc758 \uae34\uc7a5\uc774 \uc0c8 \ubcc0\uc218\ub85c \ub5a0\uc62c\ub790\ub2e4.","\uc9c0\uc815\ud559\uc758 \uade0\uc5f4\uc740 \uacf5\uae09\ub9dd \uc9c0\ub3c4 \uc704\uc5d0 \uadf8\ub824\uc9d1\ub2c8\ub2e4.",B.p)
