B.ZN=new A.l(2000,6,19,"\ubca4\ucc98 \uc790\uae08","\uc18c\ud504\ud2b8\ubc45\ud06c\uac00 \ub098\uc2a4\ub2e5\uc7ac\ud32c\uc744 \uc5f4\uc5c8\ub2e4","\uc190\uc815\uc758\uc758 \uc18c\ud504\ud2b8\ubc45\ud06c\uac00 \ubbf8\uad6d \ub098\uc2a4\ub2e5\uacfc \uc190\uc7a1\uace0 \uc77c\ubcf8\ud310 \uc2e0\uc2dc\uc7a5\uc744 \ucd9c\ubc94\uc2dc\ucf30\ub2e4. \ubca4\ucc98 \uc790\uae08 \uc870\ub2ec\uc758 \uc0c8 \ud1b5\ub85c\uac00 \uc5f4\ub838\ub2e4.","\ub3c8\uc774 \ud750\ub974\ub294 \uc0c8 \ud1b5\ub85c\uac00 \ub2e4\uc74c \uc0ac\uc774\ud074\uc758 \uc2b9\uc790\ub97c \ub9cc\ub4ed\ub2c8\ub2e4.",B.x)
B.a_i=new A.l(2000,6,26,"\uc0dd\uba85\uacf5\ud559","\uc778\uac04 \uac8c\ub188 \ucd08\uc548 \uc644\uc131\uc774 \ubc1c\ud45c\ub410\ub2e4","\uc778\uac04 \uc720\uc804\uc790 \uc9c0\ub3c4\uc758 \ucd08\uc548\uc774 \uc644\uc131\ub410\ub2e4\uace0 \ubc31\uc545\uad00\uc5d0\uc11c \uacf5\ud45c\ub410\ub2e4. \ubc14\uc774\uc624\xb7\uc81c\uc57d \uc0b0\uc5c5\uc758 \uc7a5\uae30 \uc131\uc7a5 \uc11c\uc0ac\uac00 \uc2dc\uc791\ub410\ub2e4.","\uacb0\uc2e4\uae4c\uc9c0 \uc624\ub798 \uac78\ub9ac\ub294 \uae30\uc220\uc5d4 \uc778\ub0b4\ub77c\ub294 \uc785\uc7a5\ub8cc\uac00 \ubd99\uc2b5\ub2c8\ub2e4.",B.p)
B.Um=new A.l(2000,7,1,"\uc81c\ub3c4 \ubcc0\ud654","\uc758\uc57d\ubd84\uc5c5\uc774 \ubcf8\uaca9 \uc2dc\ud589\ub410\ub2e4","\uc9c4\ub8cc\uc640 \uc870\uc81c\ub97c \ub098\ub204\ub294 \uc81c\ub3c4\uac00 \uc804\uba74 \uc2dc\ud589\ub418\uba70 \uc758\ub8cc\uacc4 \uac08\ub4f1\uc774 \uc774\uc5b4\uc84c\ub2e4. \uc81c\uc57d\xb7\uc720\ud1b5 \uc0b0\uc5c5\uc758 \ud310\uc774 \ubc14\ub00c\uc5c8\ub2e4.","\uc81c\ub3c4 \ubcc0\ud654\ub294 \uc2b9\uc790\uc640 \ud328\uc790\ub97c \ub3d9\uc2dc\uc5d0 \ub9cc\ub4e4\uc5b4 \ub0c5\ub2c8\ub2e4.",B.J)
B.W1=new A.l(2000,7,2,"\uc720\ub85c 2000","\ud504\ub791\uc2a4\uac00 \uc720\ub85c 2000 \uc6b0\uc2b9\uc744 \ucc28\uc9c0\ud588\ub2e4","\ud504\ub791\uc2a4\uac00 \uc774\ud0c8\ub9ac\uc544\ub97c \uaebe\uace0 \uc720\ub7fd\ucd95\uad6c\uc120\uc218\uad8c\uc744 \uc81c\ud328\ud588\ub2e4. \uc6d4\ub4dc\ucef5\uc5d0 \uc774\uc740 \ucd95\uad6c \uac15\uad6d\uc758 \uc804\uc131\uae30\uc600\ub2e4.","\ub300\ud615 \uc2a4\ud3ec\uce20 \uc774\ubca4\ud2b8\ub294 \uc2a4\ud3f0\uc11c\uc640 \ubbf8\ub514\uc5b4\uc5d0 \uc7a0\uae50\uc758 \ud2b9\uc218\ub97c \uc548\uae41\ub2c8\ub2e4.",B.J)
B.Z2=new A.l(2000,7,19,"\uc81c\ud488 \ucd9c\uc2dc","\uc560\ud50c\uc774 \ud30c\uc6cc\ub9e5 G4 \ud050\ube0c\ub97c \uacf5\uac1c\ud588\ub2e4","8\uc778\uce58 \uc815\uc721\uba74\uccb4\uc758 \uc2e4\ud5d8\uc801 \ub514\uc790\uc778 PC\uac00 \ub4f1\uc7a5\ud588\ub2e4. \uc560\ud50c\uc758 \ub514\uc790\uc778 \uc2b9\ubd80\uac00 \ub2e4\uc2dc \uc2dc\ud5d8\ub300\uc5d0 \uc62c\ub790\ub2e4.","\ud601\uc2e0\uc801 \ub514\uc790\uc778\uc774 \uace7 \uc0c1\uc5c5\uc801 \uc131\uacf5\uc744 \ub73b\ud558\uc9c4 \uc54a\uc2b5\ub2c8\ub2e4.",B.x)
B.YT=new A.l(2000,7,21,"G8 \uc815\uc0c1\ud68c\uc758","G8 \uc815\uc0c1\ud68c\uc758\uac00 \uc624\ud0a4\ub098\uc640\uc5d0\uc11c \uac1c\ub9c9\ud588\ub2e4","\uc77c\ubcf8\uc774 \uc8fc\ucd5c\ud55c \uc815\uc0c1\ud68c\uc758\uc5d0\uc11c 'IT \ud5cc\uc7a5'\uc73c\ub85c \ub514\uc9c0\ud138 \uaca9\ucc28 \ud574\uc18c\uac00 \ub17c\uc758\ub410\ub2e4. \uc778\ud130\ub137 \uc2dc\ub300\uc758 \uad6d\uc81c \uc758\uc81c\uac00 \ubd80\uc0c1\ud588\ub2e4.","\uc815\ucc45 \uc758\uc81c\ub85c \uc624\ub978 \uc0b0\uc5c5\uc5d4 \uc7a5\uae30 \uc790\uae08\uc774 \ubaa8\uc785\ub2c8\ub2e4.",B.p)
B.Xw=new A.l(2000,7,25,"\ud56d\uacf5 \ucc38\uc0ac","\uc5d0\uc5b4\ud504\ub791\uc2a4 \ucf69\ucf54\ub4dc\uae30\uac00 \ucd94\ub77d\ud588\ub2e4","\ud30c\ub9ac \uadfc\uad50\uc5d0\uc11c \ucd08\uc74c\uc18d \uc5ec\uac1d\uae30 \ucf69\ucf54\ub4dc\uac00 \uc774\ub959 \uc9c1\ud6c4 \ucd94\ub77d\ud588\ub2e4. \ucd08\uc74c\uc18d \uc5ec\uac1d \uc2dc\ub300\uc758 \uc2e0\ub8b0\uac00 \ud754\ub4e4\ub838\ub2e4.","\ud654\ub824\ud55c \uae30\uc220\ub3c4 \uc548\uc804 \uc55e\uc5d0\uc11c\ub294 \uc608\uc678\uac00 \uc5c6\uc2b5\ub2c8\ub2e4.",B.q)
B.X3=new A.l(2000,8,9,"\ub300\uaddc\ubaa8 \ub9ac\ucf5c","\ud30c\uc774\uc5b4\uc2a4\ud1a4\uc774 \ub300\uaddc\ubaa8 \ud0c0\uc774\uc5b4 \ub9ac\ucf5c\uc744 \ubc1c\ud45c\ud588\ub2e4","\ud3ec\ub4dc SUV\uc5d0 \uc7a5\ucc29\ub41c \ud0c0\uc774\uc5b4 \uacb0\ud568\uc73c\ub85c \ub300\uaddc\ubaa8 \ub9ac\ucf5c\uc774 \uc2dc\uc791\ub410\ub2e4. \ub450 \uac70\ub300 \uae30\uc5c5\uc758 \ucc45\uc784 \uacf5\ubc29\uc774 \uc774\uc5b4\uc84c\ub2e4.","\ud488\uc9c8 \uc0ac\uace0\ub294 \ube0c\ub79c\ub4dc \uc2e0\ub8b0\ub77c\ub294 \ubb34\ud615\uc790\uc0b0\uc744 \uac09\uc544\uba39\uc2b5\ub2c8\ub2e4.",B.q)
B.Z0=new A.l(2000,8,11,"\uae08\ub9ac \uc778\uc0c1","\uc77c\ubcf8\uc740\ud589\uc774 \uc81c\ub85c\uae08\ub9ac\ub97c \ud574\uc81c\ud588\ub2e4","\uc77c\ubcf8\uc740\ud589\uc774 \uc57d 10\ub144 \ub9cc\uc5d0 \uc815\ucc45\uae08\ub9ac\ub97c \uc62c\ub9ac\uba70 \uc81c\ub85c\uae08\ub9ac\ub97c \ub05d\ub0c8\ub2e4. \ud6d7\ub0a0 \uc131\uae09\ud55c \uacb0\uc815\uc774\ub77c\ub294 \ube44\ud310\uc744 \ubc1b\ub294\ub2e4.","\uc911\uc559\uc740\ud589\uc758 \ubc29\ud5a5 \uc804\ud658\uc740 \ubaa8\ub4e0 \uc790\uc0b0\uc758 \ud560\uc778\uc728\uc744 \ubc14\uafc9\ub2c8\ub2e4.",B.p)
B.WY=new A.l(2000,8,12,"\uc7a0\uc218\ud568 \uce68\ubab0","\ub7ec\uc2dc\uc544 \ud575\uc7a0\uc218\ud568 \ucfe0\ub974\uc2a4\ud06c\uac00 \uce68\ubab0\ud588\ub2e4","\ubc14\ub80c\uce20\ud574\uc5d0\uc11c \ud575\uc7a0\uc218\ud568\uc774 \uce68\ubab0\ud574 \uc2b9\uc870\uc6d0 118\uba85\uc774 \ubaa8\ub450 \uc228\uc84c\ub2e4. \ub7ec\uc2dc\uc544\uc758 \uc704\uae30 \ub300\uc751\uc774 \ub3c4\ub9c8\uc5d0 \uc62c\ub790\ub2e4.","\uc7ac\ub09c\uc740 \uc0ac\uc2e4 \uadf8\ub300\ub85c \uae30\ub85d\ud558\ub418, \uc2dc\uc7a5\uc740 \ub0c9\uc815\ud558\uac8c \ubd05\ub2c8\ub2e4.",B.q)
B.X7=new A.l(2000,8,15,"\uc774\uc0b0\uac00\uc871","\ub0a8\ubd81 \uc774\uc0b0\uac00\uc871\uc774 \ucc98\uc74c\uc73c\ub85c \uc0c1\ubd09\ud588\ub2e4","\uc815\uc0c1\ud68c\ub2f4\uc758 \ud6c4\uc18d\uc73c\ub85c \uc774\uc0b0\uac00\uc871\ub4e4\uc774 \ubc18\uc138\uae30 \ub9cc\uc5d0 \ub9cc\ub0ac\ub2e4. \ub0a8\ubd81 \ud654\ud574 \ubd84\uc704\uae30\uac00 \uc2e4\uc9c8\uc801 \uad50\ub958\ub85c \uc774\uc5b4\uc84c\ub2e4.","\uad00\uacc4 \uac1c\uc120\uc758 \uc628\uae30\ub294 \uacbd\ud611 \ud14c\ub9c8\ub85c \ubc88\uc9c0\uace4 \ud569\ub2c8\ub2e4.",B.p)
B.Wv=new A.l(2000,9,13,"\uc0c8 \uc6b4\uc601\uccb4\uc81c","\uc560\ud50c\uc774 \ub9e5 OS X \uacf5\uac1c \ubca0\ud0c0\ub97c \uc120\ubcf4\uc600\ub2e4","\uc560\ud50c\uc774 \ucc28\uc138\ub300 \uc6b4\uc601\uccb4\uc81c\uc758 \uacf5\uac1c \uc2dc\ud5d8\ud310\uc744 \ub0b4\ub1a8\ub2e4. \ud6d7\ub0a0 \uc544\uc774\ud3f0\uae4c\uc9c0 \uc787\ub294 \uc18c\ud504\ud2b8\uc6e8\uc5b4 \ud1a0\ub300\uac00 \ub193\uc600\ub2e4.","\ud50c\ub7ab\ud3fc\uc758 \ubfcc\ub9ac\uac00 \ubc14\ub014 \ub54c \uc7a5\uae30 \ubc29\ud5a5\uc744 \uc0b4\ud53c\uc138\uc694.",B.x)
B.a_o=new A.l(2000,9,14,"\uc81c\ud488 \ucd9c\uc2dc","\ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8\uac00 \uc708\ub3c4\uc6b0 Me\ub97c \ucd9c\uc2dc\ud588\ub2e4","\uac00\uc815\uc6a9 \uc0ac\uc6a9\uc790\ub97c \uaca8\ub0e5\ud55c \uc0c8 \uc708\ub3c4\uc6b0\uac00 \ub098\uc654\ub2e4. PC \ub300\uc911\ud654 \ud750\ub984 \uc18d \uc18c\ube44\uc790 \uc2dc\uc7a5 \uacbd\uc7c1\uc774 \uc774\uc5b4\uc84c\ub2e4.","\uc798 \ud314\ub9ac\ub294 \uc81c\ud488\uacfc \uc88b\uc740 \uc81c\ud488\uc740 \ub298 \uac19\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.",B.x)
B.ZZ=new A.l(2000,9,15,"\ub0a8\ubd81 \uacf5\ub3d9\uc785\uc7a5","\uc2dc\ub4dc\ub2c8 \uac1c\ub9c9\uc2dd\uc5d0\uc11c \ub0a8\ubd81\uc774 \uacf5\ub3d9\uc785\uc7a5\ud588\ub2e4","\ub0a8\uacfc \ubd81 \uc120\uc218\ub2e8\uc774 \ud55c\ubc18\ub3c4\uae30\ub97c \ub4e4\uace0 \ud568\uaed8 \uc785\uc7a5\ud588\ub2e4. \ud654\ud574 \ubd84\uc704\uae30\uac00 \uc138\uacc4 \ubb34\ub300\uc5d0\uc11c \uc0c1\uc9d5\uc801\uc73c\ub85c \ub4dc\ub7ec\ub0ac\ub2e4.","\uc0c1\uc9d5\uc801 \uc7a5\uba74\uc740 \ud22c\uc790\uc2ec\ub9ac\uc758 \uc628\ub3c4\ub97c \ubc14\uafb8\uae30\ub3c4 \ud569\ub2c8\ub2e4.",B.p)
B.Zf=new A.l(2000,9,15,"\uc62c\ub9bc\ud53d \uac1c\ub9c9","\uc2dc\ub4dc\ub2c8 \uc62c\ub9bc\ud53d\uc774 \uac1c\ub9c9\ud588\ub2e4","\uc0c8\ucc9c\ub144 \uccab \ud558\uacc4\uc62c\ub9bc\ud53d\uc774 \ud638\uc8fc \uc2dc\ub4dc\ub2c8\uc5d0\uc11c \ub9c9\uc744 \uc62c\ub838\ub2e4. \uc138\uacc4\uc778\uc758 \uc2dc\uc120\uc774 \uc2a4\ud3ec\uce20 \ucd95\uc81c\ub85c \ubaa8\uc600\ub2e4.","\uba54\uac00 \uc774\ubca4\ud2b8\ub294 \uac1c\ucd5c\uad6d \uc18c\ube44\uc640 \ubbf8\ub514\uc5b4\uc5d0 \ud2b9\uc218\ub97c \ubd80\ub985\ub2c8\ub2e4.",B.p)
B.Wc=new A.l(2000,10,1,"\uc62c\ub9bc\ud53d \ud3d0\ub9c9","\uc2dc\ub4dc\ub2c8 \uc62c\ub9bc\ud53d\uc774 \ub9c9\uc744 \ub0b4\ub838\ub2e4","17\uc77c\uac04\uc758 \uc5f4\uc804\uc774 \ub05d\ub098\uba70 \uc0c8\ucc9c\ub144 \uccab \uc62c\ub9bc\ud53d\uc774 \ud3d0\ub9c9\ud588\ub2e4. \ub2e4\uc74c \uac1c\ucd5c\uc9c0\ub85c \uad00\uc2ec\uc774 \uc62e\uaca8\uac14\ub2e4.","\ucd95\uc81c\uac00 \ub05d\ub098\uba74 \ub0a8\ub294 \uac74 \uc778\ud504\ub77c\uc640 \uccad\uad6c\uc11c\uc785\ub2c8\ub2e4.",B.J)
B.Yr=new A.l(2000,10,5,"\uc815\uad8c \ubd95\uad34","\ubc00\ub85c\uc170\ube44\uce58 \uc815\uad8c\uc774 \ubb34\ub108\uc84c\ub2e4","\ub300\uaddc\ubaa8 \uc2dc\uc704 \ub05d\uc5d0 \uc720\uace0 \ub300\ud1b5\ub839\uc774 \uad8c\uc88c\uc5d0\uc11c \ubb3c\ub7ec\ub0ac\ub2e4. \ubc1c\uce78\uc758 \uc624\ub79c \uac08\ub4f1\uc774 \uc804\ud658\uc810\uc744 \ub9de\uc558\ub2e4.","\uccb4\uc81c \uc804\ud658\uc740 \uc9c0\uc5ed \ub9ac\uc2a4\ud06c\uc758 \uc7ac\ud3c9\uac00\ub97c \ubd80\ub985\ub2c8\ub2e4.",B.p)
B.Z8=new A.l(2000,10,12,"\ud14c\ub7ec \uacf5\uaca9","\ubbf8 \uad6c\ucd95\ud568 \ucf5c\ud568\uc774 \ud14c\ub7ec \uacf5\uaca9\uc744 \ubc1b\uc558\ub2e4","\uc608\uba58 \uc544\ub374\ud56d\uc5d0\uc11c \ubbf8 \ud574\uad70 \uad6c\ucd95\ud568\uc774 \uc790\ud3ed \uacf5\uaca9\uc744 \ub2f9\ud588\ub2e4. \uc0c8\ub85c\uc6b4 \ud615\ud0dc\uc758 \ud14c\ub7ec \uc704\ud611\uc774 \ubd80\uac01\ub410\ub2e4.","\uc548\ubcf4 \ubd88\uc548\uc740 \uc720\uac00\uc640 \ubc29\uc704 \uad00\ub828 \uc2ec\ub9ac\ub97c \uc790\uadf9\ud569\ub2c8\ub2e4.",B.q)
B.Wh=new A.l(2000,10,13,"\ub178\ubca8\uc0c1","\uae40\ub300\uc911 \ub300\ud1b5\ub839\uc774 \ub178\ubca8\ud3c9\ud654\uc0c1 \uc218\uc0c1\uc790\ub85c \uc120\uc815\ub410\ub2e4","\ub0a8\ubd81 \ud654\ud574\uc640 \ubbfc\uc8fc\uc8fc\uc758 \uae30\uc5ec\ub85c \ub178\ubca8\ud3c9\ud654\uc0c1 \uc218\uc0c1\uc774 \uacb0\uc815\ub410\ub2e4. \ud55c\uad6d\uc758 \uad6d\uc81c\uc801 \uc704\uc0c1\uc774 \ub192\uc544\uc84c\ub2e4.","\uad6d\uac00 \uc2e0\uc778\ub3c4\uc758 \uc0c1\uc2b9\uc740 \ucf54\ub9ac\uc544 \ub514\uc2a4\uce74\uc6b4\ud2b8\ub97c \ub20c\ub7ec \uc90d\ub2c8\ub2e4.",B.p)
B.UL=new A.l(2000,10,26,"\ucf58\uc194 \ucd9c\uc2dc","\ud50c\ub808\uc774\uc2a4\ud14c\uc774\uc1582\uac00 \ubd81\ubbf8\uc5d0 \ucd9c\uc2dc\ub410\ub2e4","\uc18c\ub2c8\uc758 \ucc28\uc138\ub300 \uac8c\uc784\uae30\uac00 \ubbf8\uad6d \uc2dc\uc7a5\uc5d0 \uc0c1\ub959\ud574 \ud488\uadc0\ub97c \ube5a\uc5c8\ub2e4. \uac8c\uc784\uc774 \uac70\ub300 \uc5d4\ud130\ud14c\uc778\uba3c\ud2b8 \uc0b0\uc5c5\uc73c\ub85c \ucee4\uc84c\ub2e4.","\ud3ed\ubc1c\uc801 \uc218\uc694 \ub4a4\uc5d4 \uacf5\uae09\ub9dd\uc774 \uc9c4\uc9dc \uc2e4\ub825\uc744 \uc99d\uba85\ud569\ub2c8\ub2e4.",B.x)
B.Yp=new A.l(2000,11,2,"\uc6b0\uc8fc \uc0c1\uc8fc","\uad6d\uc81c\uc6b0\uc8fc\uc815\uac70\uc7a5\uc5d0 \uccab \uc0c1\uc8fc\uac00 \uc2dc\uc791\ub410\ub2e4","\uccab \uc7a5\uae30 \uccb4\ub958 \uc6b0\uc8fc\uc778\ub4e4\uc774 \uad6d\uc81c\uc6b0\uc8fc\uc815\uac70\uc7a5\uc5d0 \uc785\uc8fc\ud588\ub2e4. \uc778\ub958\uc758 \uc0c1\uc2dc \uc6b0\uc8fc \uac70\uc8fc \uc2dc\ub300\uac00 \uc5f4\ub838\ub2e4.","\uba40\uc5b4 \ubcf4\uc774\ub294 \ud504\ub7f0\ud2f0\uc5b4\ub3c4 \uc0b0\uc5c5\uc758 \uc528\uc557\uc774 \ub429\ub2c8\ub2e4.",B.p)
B.ZO=new A.l(2000,11,7,"\uac1c\ud45c \ud63c\ub780","\ubbf8\uad6d \ub300\uc120\uc774 \uac1c\ud45c \ud63c\ub780\uc5d0 \ube60\uc84c\ub2e4","\ubd80\uc2dc\uc640 \uace0\uc5b4\uac00 \ucd08\ubc15\ube59\uc744 \uc774\ub8e8\uba70 \ud50c\ub85c\ub9ac\ub2e4 \uc7ac\uac80\ud45c \ub17c\ub780\uc774 \ubd88\uac70\uc84c\ub2e4. \uc815\uce58 \ubd88\ud655\uc2e4\uc131\uc774 \uc2dc\uc7a5\uc744 \uc9d3\ub20c\ub800\ub2e4.","\ubd88\ud655\uc2e4\uc131 \uadf8 \uc790\uccb4\uac00 \uc2dc\uc7a5\uc774 \uc2eb\uc5b4\ud558\ub294 \uc545\uc7ac\uc785\ub2c8\ub2e4.",B.q)
B.Uj=new A.l(2000,11,8,"\uae30\uc5c5 \ubd80\ub3c4","\ub300\uc6b0\uc790\ub3d9\ucc28\uac00 \ucd5c\uc885 \ubd80\ub3c4 \ucc98\ub9ac\ub410\ub2e4","\uad6c\uc870\uc870\uc815 \ud611\uc0c1\uc774 \ubb34\uc0b0\ub418\uba70 \ub300\uc6b0\ucc28\uac00 \ubc95\uc815\uad00\ub9ac \uc808\ucc28\uc5d0 \ub4e4\uc5b4\uac14\ub2e4. \uc678\ud658\uc704\uae30 \ud6c4 \uc7ac\ubc8c \uad6c\uc870\uc870\uc815\uc758 \uc0c1\uc9d5\uc774 \ub410\ub2e4.","\ube5a \ub9ce\uc740 \uac70\uc778\uc758 \ubab0\ub77d\uc740 \ud611\ub825\uc5c5\uccb4\ub85c \ud30c\ubb38\uc744 \ub113\ud799\ub2c8\ub2e4.",B.q)
B.Wm=new A.l(2000,11,11,"\ud654\uc7ac \ucc38\uc0ac","\uc624\uc2a4\ud2b8\ub9ac\uc544 \uce74\ud504\ub8ec \ucf00\uc774\ube14\uce74\uc5d0\uc11c \ud654\uc7ac\uac00 \ub0ac\ub2e4","\uc54c\ud504\uc2a4 \uc0b0\uc545\uc5f4\ucc28 \ud130\ub110\uc5d0\uc11c \ubd88\uc774 \ub098 155\uba85\uc774 \ubaa9\uc228\uc744 \uc783\uc5c8\ub2e4. \uad00\uad11 \uc548\uc804 \uad00\ub9ac\uc5d0 \uacbd\uc885\uc774 \uc6b8\ub838\ub2e4.","\uc548\uc804 \uaddc\uc81c \uac15\ud654\ub294 \uad00\ub828 \uc0b0\uc5c5\uc758 \ube44\uc6a9 \uad6c\uc870\ub97c \ubc14\uafc9\ub2c8\ub2e4.",B.q)
B.Wo=new A.l(2000,12,10,"\ub178\ubca8\uc0c1 \uc218\uc0c1","\uae40\ub300\uc911 \ub300\ud1b5\ub839\uc774 \ub178\ubca8\ud3c9\ud654\uc0c1\uc744 \ubc1b\uc558\ub2e4","\uc624\uc2ac\ub85c \uc2dc\uc0c1\uc2dd\uc5d0\uc11c \uae40\ub300\uc911 \ub300\ud1b5\ub839\uc774 \ub178\ubca8\ud3c9\ud654\uc0c1\uc744 \uc218\uc0c1\ud588\ub2e4. \ud55c\ubc18\ub3c4 \ud3c9\ud654 \ub178\ub825\uc774 \uc138\uacc4\uc758 \uc778\uc815\uc744 \ubc1b\uc558\ub2e4.","\uad6d\uc81c\uc801 \uc778\uc815\uc740 \uad6d\uac00 \ube0c\ub79c\ub4dc\ub77c\ub294 \ubb34\ud615\uc790\uc0b0\uc744 \ud0a4\uc6c1\ub2c8\ub2e4.",B.p)
B.Vj=new A.l(2000,12,12,"\ub300\uc120 \ud655\uc815","\ubbf8 \ub300\ubc95\uc6d0 \ud310\uacb0\ub85c \ubd80\uc2dc \ub2f9\uc120\uc774 \ud655\uc815\ub410\ub2e4","\uc5f0\ubc29\ub300\ubc95\uc6d0\uc774 \uc7ac\uac80\ud45c \uc911\ub2e8\uc744 \uacb0\uc815\ud558\uba70 \ubd80\uc2dc\uc758 \uc2b9\ub9ac\uac00 \uad73\uc5b4\uc84c\ub2e4. \ud55c \ub2ec\uc744 \ub048 \uc815\uce58 \ubd88\ud655\uc2e4\uc131\uc774 \ud574\uc18c\ub410\ub2e4.","\ubd88\ud655\uc2e4\uc131\uc758 \ud574\uc18c\ub9cc\uc73c\ub85c\ub3c4 \uc2dc\uc7a5\uc740 \uc548\ub3c4\ud569\ub2c8\ub2e4.",B.p)
B.UN=new A.l(2000,12,15,"3G \uc0ac\uc5c5\uc790","SK\ud154\ub808\ucf64\xb7KT\uac00 IMT-2000 \uc0ac\uc5c5\uc790\ub85c \uc120\uc815\ub410\ub2e4","\ucc28\uc138\ub300 \uc774\ub3d9\ud1b5\uc2e0(3G) \uc0ac\uc5c5\uad8c\uc774 \ubc30\ubd84\ub418\uba70 \ud1b5\uc2e0\uc0ac \uacbd\uc7c1 \uad6c\ub3c4\uac00 \uc9dc\uc600\ub2e4. \ubaa8\ubc14\uc77c \uc778\ud130\ub137 \uc2dc\ub300\uc758 \ucc44\ube44\uac00 \uc2dc\uc791\ub410\ub2e4.","\ub2e4\uc74c \uc138\ub300 \ud45c\uc900\uc744 \uc954 \uc790\uac00 \ub2e4\uc74c \uc131\uc7a5\uc744 \uac00\uc838\uac11\ub2c8\ub2e4.",B.p)
B.Zl=new A.l(2000,12,26,"\ubc84\ube14 \ubd95\uad34","\ucf54\uc2a4\ub2e5\uc774 \uc5f0\uc911 \ucd5c\uc800\ub85c \ucd94\ub77d\ud588\ub2e4","\uace0\uc810 \ub300\ube44 80% \ub118\uac8c \ube60\uc9c0\uba70 \ucf54\uc2a4\ub2e5\uc774 \ud55c \ud574\ub97c \ucd5c\uc800\uc810\uc73c\ub85c \ub9c8\uac10\ud588\ub2e4. IT \ubc84\ube14\uc758 \uc0c1\ud754\uc774 \ub69c\ub837\ud588\ub2e4.","\ubc84\ube14\uc774 \ub0a8\uae34 \ud3d0\ud5c8\uc5d0\uc11c \uc9c4\uc9dc \uae30\uc5c5\uc774 \uac00\ub824\uc9d1\ub2c8\ub2e4.",B.q)
B.Vn=new A.l(2001,1,1,"\ub300\ud45c\ud300","\ud788\ub529\ud06c, \ud55c\uad6d \ucd95\uad6c\ub300\ud45c\ud300 \uc9c0\ud718\ubd09","2002 \uc6d4\ub4dc\ucef5\uc744 1\ub144\uc5ec \uc55e\ub450\uace0 \uac70\uc2a4 \ud788\ub529\ud06c \uac10\ub3c5\uc774 \ub300\ud45c\ud300\uc744 \ub9e1\uc558\ub2e4. \uc628 \ub098\ub77c\uc758 \uae30\ub300\uac00 \ucd95\uad6c\ub85c \ud5a5\ud55c\ub2e4.","\uc548\ubc29 \uc6d4\ub4dc\ucef5\uc774 \ub2e4\uac00\uc635\ub2c8\ub2e4. \uc0ac\ub78c\ub4e4\uc758 \uad00\uc2ec\uc774 \uc5b4\ub514\ub85c \ud750\ub97c\uc9c0 \uc9c0\ucf1c\ubcf4\uc138\uc694.",B.p)
B.Xx=new A.l(2001,1,3,"\uae34\uae09 \uae08\ub9ac\uc778\ud558","\u7f8e \uc5f0\uc900, \uc608\uace0 \uc5c6\ub294 0.5%p \uae08\ub9ac\uc778\ud558","\uacbd\uae30 \ub454\ud654 \uc6b0\ub824\uc5d0 \uc5f0\uc900\uc774 \uc815\ub840\ud68c\uc758 \ubc16\uc5d0\uc11c \uae30\uc2b5 \uc778\ud558\ub97c \ub2e8\ud589\ud588\ub2e4. \ub098\uc2a4\ub2e5\uc774 \ud558\ub8e8 \ub9cc\uc5d0 \uae09\ub4f1\ud588\ub2e4.","\uc911\uc559\uc740\ud589\uc774 \uc11c\ub450\ub978\ub2e4\ub294 \uac74 \uadf8\ub9cc\ud07c \uc0c1\ud669\uc774 \uae09\ud558\ub2e4\ub294 \uc2e0\ud638\uc774\uae30\ub3c4 \ud569\ub2c8\ub2e4.",B.q)
B.VR=new A.l(2001,1,9,"\uc81c\ud488 \uacf5\uac1c","\uc560\ud50c, \uc74c\uc545 \uad00\ub9ac \uc571 \uc544\uc774\ud2a0\uc988 \uacf5\uac1c","\ub9e5\uc6d4\ub4dc\uc5d0\uc11c \ub514\uc9c0\ud138 \uc74c\uc545\uc744 \uc815\ub9ac\ud558\uace0 \uc7ac\uc0dd\ud558\ub294 \uc544\uc774\ud2a0\uc988\uac00 \ubc1c\ud45c\ub410\ub2e4. \uc560\ud50c\uc774 \uc74c\uc545\uc73c\ub85c \ubc1c\uc744 \ub113\ud78c\ub2e4.","\uc9c0\uae08\uc740 \uc791\uc740 \uc571\uc774\uc9c0\ub9cc \uc0dd\ud0dc\uacc4\uc758 \uc528\uc557\uc774 \ub420 \uc218\ub3c4 \uc788\uc2b5\ub2c8\ub2e4.",B.x)
B.Xk=new A.l(2001,1,15,"\uc778\ud130\ub137","\ub204\uad6c\ub098 \uace0\uce58\ub294 \ubc31\uacfc\uc0ac\uc804 \uc704\ud0a4\ud53c\ub514\uc544 \uc2dc\uc791","\uc628\ub77c\uc778 \ubb34\ub8cc \ubc31\uacfc\uc0ac\uc804 \uc704\ud0a4\ud53c\ub514\uc544\uac00 \ubb38\uc744 \uc5f4\uc5c8\ub2e4. \uc9d1\ub2e8\uc9c0\uc131\uc73c\ub85c \uc9c0\uc2dd\uc744 \ub9cc\ub4dc\ub294 \uc2e4\ud5d8\uc774 \uc2dc\uc791\ub410\ub2e4.","\ub3c8\uc774 \uc548 \ub418\uc5b4 \ubcf4\uc774\ub294 \uc2e4\ud5d8\uc5d0\uc11c \uc138\uc0c1\uc744 \ubc14\uafb8\ub294 \uac83\uc774 \ub098\uc624\uace4 \ud569\ub2c8\ub2e4.",B.x)
B.ZI=new A.l(2001,1,20,"\u7f8e \ub300\ud1b5\ub839","\uc870\uc9c0 W. \ubd80\uc2dc, 43\ub300 \ubbf8 \ub300\ud1b5\ub839 \ucde8\uc784","\uacf5\ud654\ub2f9 \ubd80\uc2dc \ud589\uc815\ubd80\uac00 \ucd9c\ubc94\ud588\ub2e4. \uac10\uc138\uc640 \uaddc\uc81c \uc644\ud654\ub97c \uc608\uace0\ud558\uba70 \uc2dc\uc7a5\uc758 \uc148\ubc95\uc774 \ub2ec\ub77c\uc9c4\ub2e4.","\uc815\uad8c\uc774 \ubc14\ub00c\uba74 \uc138\uae08\uacfc \uaddc\uc81c\uc758 \ubc29\ud5a5\ub3c4 \ubc14\ub01d\ub2c8\ub2e4.",B.p)
B.Yn=new A.l(2001,1,26,"\uc9c0\uc9c4","\uc778\ub3c4 \uad6c\uc790\ub77c\ud2b8 \ub300\uc9c0\uc9c4","\uc778\ub3c4 \uc11c\ubd80\uc5d0\uc11c \uac15\uc9c4\uc774 \uc77c\uc5b4\ub098 \uc218\ub9cc \uba85\uc774 \ubaa9\uc228\uc744 \uc783\uc5c8\ub2e4. \uad11\ubc94\uc704\ud55c \ud53c\ud574\uac00 \uc774\uc5b4\uc84c\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uae30\ub85d\ud569\ub2c8\ub2e4.",B.q)
B.YX=new A.l(2001,1,31,"\ucf58\uc194 \ucca0\uc218","\uc138\uac00, \ucf58\uc194 \uc811\uace0 \ub4dc\ub9bc\uce90\uc2a4\ud2b8 \uc911\ub2e8","\uc138\uac00\uac00 \ud558\ub4dc\uc6e8\uc5b4 \uacbd\uc7c1\uc744 \ud3ec\uae30\ud558\uace0 \uc18c\ud504\ud2b8\uc6e8\uc5b4 \ud68c\uc0ac\ub85c \uc804\ud658\ud55c\ub2e4\uace0 \ubc1d\ud614\ub2e4. \ucf58\uc194 \uc804\uc7c1\uc758 \ud310\ub3c4\uac00 \ud754\ub4e4\ub9b0\ub2e4.","1\ub4f1\uc774 \uc544\ub2c8\uba74 \uc811\ub294 \uacb0\ub2e8, \ubc84\ud2f0\uae30\uc640 \uc811\uae30 \uc0ac\uc774\ub97c \uc0dd\uac01\ud558\uac8c \ud569\ub2c8\ub2e4.",B.q)
B.Wa=new A.l(2001,2,6,"\uc774\uc2a4\ub77c\uc5d8 \ucd1d\uc120","\uc774\uc2a4\ub77c\uc5d8 \ucd1d\ub9ac\uc5d0 \uc544\ub9ac\uc5d8 \uc0e4\ub860 \ub2f9\uc120","\uac15\uacbd\ud30c \uc0e4\ub860\uc774 \ucd1d\ub9ac\uc5d0 \uc62c\ub790\ub2e4. \uc911\ub3d9 \uc815\uc138\uc758 \uae34\uc7a5\uc774 \ud55c\uce35 \ub192\uc544\uc9c4\ub2e4.","\uc9c0\uc815\ud559 \ub9ac\uc2a4\ud06c\ub294 \uc720\uac00\uc640 \uc548\uc804\uc790\uc0b0\uc73c\ub85c \ubc88\uc9c0\uace4 \ud569\ub2c8\ub2e4.",B.p)
B.Xr=new A.l(2001,2,9,"\ud574\uc0c1 \uc0ac\uace0","\u7f8e \uc7a0\uc218\ud568, \uc77c \uc2e4\uc2b5\uc120 \uc5d0\ud788\uba54\ub9c8\ub8e8 \ucda9\ub3cc","\ud558\uc640\uc774 \uc55e\ubc14\ub2e4\uc5d0\uc11c \ubbf8 \ud574\uad70 \uc7a0\uc218\ud568\uc774 \uc77c\ubcf8 \uace0\uad50 \uc2e4\uc2b5\uc120\uc744 \ub4e4\uc774\ubc1b\uc544 9\uba85\uc774 \uc228\uc84c\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uc804\ud569\ub2c8\ub2e4.",B.q)
B.Vt=new A.l(2001,2,12,"\uc6b0\uc8fc \ud0d0\uc0ac","NASA \ud0d0\uc0ac\uc120, \uc18c\ud589\uc131 \uc5d0\ub85c\uc2a4 \uccab \ucc29\ub959","\ub2c8\uc5b4\uc288\uba54\uc774\ucee4\uac00 \uc18c\ud589\uc131 \ud45c\uba74\uc5d0 \uc0ac\uc0c1 \ucc98\uc74c\uc73c\ub85c \ub0b4\ub824\uc549\uc558\ub2e4. \uc778\ub958\uc758 \ud0d0\uc0ac \uc601\uc5ed\uc774 \ub113\uc5b4\uc84c\ub2e4.","\uba3c \ubbf8\ub798\uc758 \uae30\uc220\ub3c4 \uc5b8\uc820\uac00 \uc0b0\uc5c5\uc774 \ub429\ub2c8\ub2e4.",B.p)
B.XA=new A.l(2001,2,12,"\uc800\uc791\uad8c \ud310\uacb0","\ub0c5\uc2a4\ud130, \ud56d\uc18c\uc2ec \ud328\uc18c\ub85c \uc874\ud3d0 \uae30\ub85c","\ubc95\uc6d0\uc774 \uc74c\uc545 \ubb34\ub2e8 \uacf5\uc720\ub97c \ub9c9\uc73c\ub77c\uace0 \ud310\uacb0\ud588\ub2e4. \ubb34\ub8cc \uacf5\uc720 \uc11c\ube44\uc2a4\uc758 \uc55e\ub0a0\uc774 \ubd88\ud22c\uba85\ud574\uc84c\ub2e4.","\uacf5\uc9dc \uc778\uae30\uc640 \uc9c0\uc18d \uac00\ub2a5\ud55c \uc0ac\uc5c5\uc740 \ub2e4\ub978 \ubb38\uc81c\uc785\ub2c8\ub2e4.",B.q)
B.XN=new A.l(2001,3,4,"\ud654\uc7ac","\uc11c\uc6b8 \ud64d\uc81c\ub3d9 \ud654\uc7ac, \uc18c\ubc29\uad00 6\uba85 \uc21c\uc9c1","\uc8fc\ud0dd \ud654\uc7ac \uc9c4\uc555 \uc911 \uac74\ubb3c\uc774 \ubb34\ub108\uc838 \uc18c\ubc29\uad00\ub4e4\uc774 \uc21c\uc9c1\ud588\ub2e4. \uc548\uc804 \ub300\uc751 \uccb4\uacc4\ub97c \ub3cc\uc544\ubcf4\uac8c \ud588\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uc804\ud569\ub2c8\ub2e4.",B.q)
B.Wl=new A.l(2001,3,8,"\ubb38\ud654\uc7ac \ud30c\uad34","\ud0c8\ub808\ubc18, \ubc14\ubbf8\uc580 \ub300\ubd88 \ud3ed\ud30c","\uc544\ud504\uac00\ub2c8\uc2a4\ud0c4 \ud0c8\ub808\ubc18\uc774 1500\ub144 \ub41c \uc11d\ubd88\uc744 \ud3ed\ud30c\ud588\ub2e4. \uc778\ub958 \uacf5\ub3d9\uc758 \uc720\uc0b0\uc774 \uc0ac\ub77c\uc84c\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uae30\ub85d\ud569\ub2c8\ub2e4.",B.q)
B.XX=new A.l(2001,3,9,"\uac10\uc6d0","\uc2dc\uc2a4\ucf54, \ucd5c\ub300 8\ucc9c \uba85 \uac10\uc6d0 \uc608\uace0","\ub124\ud2b8\uc6cc\ud06c \uc7a5\ube44 \ub300\ud45c\uc8fc\uc790\uac00 \ucc3d\uc0ac \uc774\ub798 \uccab \ub300\uaddc\ubaa8 \uac10\uc6d0\uc744 \uc608\uace0\ud588\ub2e4. \ud1b5\uc2e0\xb7\uc778\ud130\ub137 \ud22c\uc790 \uac70\ud488\uc774 \uaebc\uc9c0\uace0 \uc788\ub2e4.","\uc798\ub098\uac00\ub358 \uc131\uc7a5\uc8fc\ub3c4 \uc218\uc694\uac00 \uc2dd\uc73c\uba74 \ud754\ub4e4\ub9bd\ub2c8\ub2e4.",B.q)
B.Vo=new A.l(2001,3,9,"\ubc18\ub3c4\uccb4 \uad6c\uc870\uc870\uc815","\ud604\ub300\uc804\uc790, \uc0ac\uba85 '\ud558\uc774\ub2c9\uc2a4\ubc18\ub3c4\uccb4'\ub85c \uad50\uccb4","\ud604\ub300\uadf8\ub8f9\uc5d0\uc11c \ub5a8\uc5b4\uc838 \ub098\uc628 \ubc18\ub3c4\uccb4 \ud68c\uc0ac\uac00 \uc0c8 \uc774\ub984\uc73c\ub85c \ud640\ub85c\uc11c\uae30\ub97c \uc2dc\uc791\ud588\ub2e4. \uc720\ub3d9\uc131 \uc704\uae30\uac00 \uadf8\ub9bc\uc790\ub97c \ub4dc\ub9ac\uc6b4\ub2e4.","\uc774\ub984\uc744 \ubc14\uafd4\ub3c4 \ube5a\uc740 \ub0a8\uc2b5\ub2c8\ub2e4. \uc7ac\ubb34 \uac74\uc804\uc131\ubd80\ud130 \ubcf4\uc138\uc694.",B.q)
B.W3=new A.l(2001,3,21,"\ud734\ub300\uac8c\uc784\uae30","\ub2cc\ud150\ub3c4 \uac8c\uc784\ubcf4\uc774 \uc5b4\ub4dc\ubc34\uc2a4, \uc77c\ubcf8 \ubc1c\ub9e4","\ud734\ub300\uc6a9 \uac8c\uc784\uae30 \uc2e0\uc81c\ud488\uc774 \uc77c\ubcf8\uc5d0\uc11c \ucd9c\uc2dc\ub410\ub2e4. \uce68\uccb4\ub41c \uac8c\uc784 \uc2dc\uc7a5\uc5d0 \ud65c\ub825\uc744 \ubd88\uc5b4\ub123\ub294\ub2e4.","\ubd88\ud669\uc5d0\ub3c4 \ud314\ub9ac\ub294 \ubb3c\uac74\uc774 \uc788\uc2b5\ub2c8\ub2e4. \uafb8\uc900\ud55c \uc218\uc694\ub97c \ub208\uc5ec\uaca8\ubcf4\uc138\uc694.",B.x)
B.a_4=new A.l(2001,3,23,"\uc6b0\uc8fc","\ub7ec \uc6b0\uc8fc\uc815\uac70\uc7a5 \ubbf8\ub974, \ud1b5\uc81c \ub099\ud558\ub85c \ud1f4\uc5ed","15\ub144\uc744 \ub3c8 \uc6b0\uc8fc\uc815\uac70\uc7a5 \ubbf8\ub974\uac00 \ub0a8\ud0dc\ud3c9\uc591\uc5d0 \ub5a8\uc5b4\uc9c0\uba70 \uc784\ubb34\ub97c \ub9c8\ucce4\ub2e4. \ud55c \uc2dc\ub300\uac00 \uc800\ubb3c\uc5c8\ub2e4.","\ubaa8\ub4e0 \uc790\uc0b0\uc5d0\ub294 \uc218\uba85\uc774 \uc788\uc2b5\ub2c8\ub2e4.",B.p)
B.Y6=new A.l(2001,3,24,"\uc6b4\uc601\uccb4\uc81c","\uc560\ud50c, \uc0c8 \uc6b4\uc601\uccb4\uc81c \ub9e5 OS X \ucd9c\uc2dc","\uc560\ud50c\uc774 \uc644\uc804\ud788 \uc0c8\ub85c \ub9cc\ub4e0 \uc6b4\uc601\uccb4\uc81c\ub97c \ub0b4\ub1a8\ub2e4. \uc774\ud6c4 \uc560\ud50c \uc81c\ud488\uad70\uc758 \ubf08\ub300\uac00 \ub41c\ub2e4.","\uac89\ubaa8\uc2b5\ubcf4\ub2e4 \ud1a0\ub300\ub97c \ubc14\uafb8\ub294 \ud22c\uc790\uac00 \uc624\ub798\uac11\ub2c8\ub2e4.",B.x)
B.ZB=new A.l(2001,3,29,"\uad00\ubb38 \uac1c\ud56d","\uc778\ucc9c\uad6d\uc81c\uacf5\ud56d \uac1c\ud56d","8\ub144 \uacf5\uc0ac \ub05d\uc5d0 \ub3d9\ubd81\uc544 \ud5c8\ube0c\ub97c \ub178\ub9b0 \uc0c8 \uad6d\uc81c\uacf5\ud56d\uc774 \ubb38\uc744 \uc5f4\uc5c8\ub2e4. \ud55c\uad6d\uc758 \ud558\ub298\uae38\uc774 \ub113\uc5b4\uc84c\ub2e4.","\ud070 \uc778\ud504\ub77c\ub294 \uc644\uacf5\uc774 \ub05d\uc774 \uc544\ub2c8\ub77c \uc2dc\uc791\uc785\ub2c8\ub2e4.",B.p)
