B.Ve=new A.l(2001,4,10,"\uad6c\uc870\uc870\uc815 \uc9c4\ud1b5","\ub300\uc6b0\ucc28 \ubd80\ud3c9\uacf5\uc7a5, \uc815\ub9ac\ud574\uace0 \ub193\uace0 \ucda9\ub3cc","\ub9e4\uac01\uc744 \uc55e\ub454 \ub300\uc6b0\uc790\ub3d9\ucc28\uc5d0\uc11c \ub300\uaddc\ubaa8 \uc815\ub9ac\ud574\uace0\uc5d0 \ubc18\ubc1c\ud558\ub294 \ucda9\ub3cc\uc774 \ubc8c\uc5b4\uc84c\ub2e4. \uc7ac\ubc8c \uad6c\uc870\uc870\uc815\uc758 \uc544\ud514\uc774 \ub4dc\ub7ec\ub0ac\ub2e4.","\uad6c\uc870\uc870\uc815\uc740 \uc22b\uc790 \ub4a4\uc5d0 \uc0ac\ub78c\uc774 \uc788\uc2b5\ub2c8\ub2e4.",B.q)
