B.Zk=new A.l(2001,8,13,"\ud55c\uc77c \uac08\ub4f1","\uace0\uc774\uc988\ubbf8, \uc57c\uc2a4\ucfe0\ub2c8 \uc2e0\uc0ac \ucc38\ubc30","\uc77c\ubcf8 \ucd1d\ub9ac\uac00 \uc804\ubc94\uc774 \ud569\uc0ac\ub41c \uc2e0\uc0ac\ub97c \ucc38\ubc30\ud588\ub2e4. \ud55c\uad6d\uacfc \uc911\uad6d\uc774 \uac15\ud558\uac8c \ubc18\ubc1c\ud588\ub2e4.","\uc678\uad50 \ub9c8\ucc30\uc740 \uad50\uc5ed\xb7\uad00\uad11\xb7\uc5ec\ub860\uc5d0 \uc2a4\uba70\ub4ed\ub2c8\ub2e4.",B.q)
B.VS=new A.l(2001,8,23,"IMF \uc878\uc5c5","\ud55c\uad6d, IMF \uad6c\uc81c\uae08\uc735 \uc870\uae30 \uc0c1\ud658 \uc644\ub8cc","\uc678\ud658\uc704\uae30 \ub54c \ube4c\ub9b0 \ub3c8\uc744 \uc608\uc815\ubcf4\ub2e4 \uc55e\ub2f9\uaca8 \ubaa8\ub450 \uac1a\uc558\ub2e4. '\uc544\uc774\uc5e0\uc5d0\ud504 \uc2dc\ub300'\uac00 \uacf5\uc2dd\uc801\uc73c\ub85c \ub05d\ub0ac\ub2e4.","\ube5a\uc744 \uac1a\ub294 \uc21c\uac04 \uc9c4\uc9dc \ud68c\ubcf5\uc774 \uc2dc\uc791\ub429\ub2c8\ub2e4.",B.p)
B.Vp=new A.l(2001,8,24,"\uac1c\ubc1c \uc644\ub8cc","\ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8, \uc708\ub3c4\uc6b0 XP \uac1c\ubc1c \uc644\ub8cc","\uc708\ub3c4\uc6b0 XP\uac00 \uc81c\uc870\uc0ac\uc5d0 \ubc30\ud3ec\ub418\uba70 \ucd9c\uc2dc \uc900\ube44\ub97c \ub9c8\ucce4\ub2e4. \uc0c8 PC \ud45c\uc900\uc758 \ub4f1\uc7a5\uc774 \ucd08\uc77d\uae30\uc5d0 \ub4e4\uc5b4\uac14\ub2e4.","\uc81c\ud488\uc774 \uc644\uc131\ub418\uba74 \ub2e4\uc74c \uad00\ubb38\uc740 \uc2dc\uc7a5\uc758 \ubc18\uc751\uc785\ub2c8\ub2e4.",B.p)
B.XB=new A.l(2001,9,1,"\ucd08\uace0\uc18d\uc778\ud130\ub137","\uc18c\ud504\ud2b8\ubc45\ud06c, \uc57c\ud6c4!BB \ucd08\uace0\uc18d\uc778\ud130\ub137 \uac1c\uc2dc","\uc18c\ud504\ud2b8\ubc45\ud06c\uac00 \uac12\uc2fc \uace0\uc18d ADSL \uc11c\ube44\uc2a4\ub97c \uc2dc\uc791\ud558\uba70 \uc694\uae08 \uacbd\uc7c1\uc5d0 \ubd88\uc744 \ubd99\uc600\ub2e4. \uc77c\ubcf8\uc758 \uc778\ud130\ub137 \ubcf4\uae09\uc774 \ube68\ub77c\uc9c4\ub2e4.","\uac00\uaca9 \ud30c\uad34\ub294 \uc810\uc720\uc728\uc744 \uc0bc\ud0a4\uc9c0\ub9cc \ucd9c\ud608\ub3c4 \ud07d\ub2c8\ub2e4.",B.x)
B.WB=new A.l(2001,9,3,"\ube45\ub51c","HP, \ucef4\ud329 \uc778\uc218 \ubc1c\ud45c","\ud734\ub81b\ud329\ucee4\ub4dc\uac00 \ucef4\ud329\uc744 \uc0ac\ub4e4\uc774\ub294 \ub300\ud615 \ud569\ubcd1\uc744 \ubc1c\ud45c\ud588\ub2e4. PC \uc5c5\uacc4\uc758 \uc9c0\uac01\ubcc0\ub3d9\uc774 \uc608\uace0\ub410\ub2e4.","\ud070 \ud569\ubcd1\uc77c\uc218\ub85d \ud1b5\ud569\uc758 \uc131\ud328\uac00 \uc9c4\uc9dc \uc2b9\ubd80\uc785\ub2c8\ub2e4.",B.p)
B.YL=new A.l(2001,9,10,"\uad11\uc6b0\ubcd1","\uc77c\ubcf8, \uc544\uc2dc\uc544 \uccab \uad11\uc6b0\ubcd1 \ud655\uc9c4","\uc77c\ubcf8\uc5d0\uc11c \uc544\uc2dc\uc544 \ucd5c\ucd08\ub85c \uad11\uc6b0\ubcd1\uc5d0 \uac78\ub9b0 \uc18c\uac00 \ud655\uc778\ub410\ub2e4. \uba39\uac70\ub9ac \ubd88\uc548\uc774 \ubc88\uc84c\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uc804\ud569\ub2c8\ub2e4.",B.q)
B.Wn=new A.l(2001,9,11,"\ud14c\ub7ec","9\xb711 \ud14c\ub7ec, \ub274\uc695\xb7\uc6cc\uc2f1\ud134 \ud53c\uaca9","\uc5ec\uac1d\uae30 \ub124 \ub300\uac00 \ub0a9\uce58\ub3fc \uc138\uacc4\ubb34\uc5ed\uc13c\ud130\uc640 \uad6d\ubc29\ubd80 \ub4f1\uc744 \uac15\ud0c0\ud588\uace0 \uc57d 3\ucc9c \uba85\uc774 \uc228\uc84c\ub2e4. \uc138\uacc4\uac00 \uba48\ucdb0 \uc130\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uc804\ud569\ub2c8\ub2e4. \uc2dc\uc7a5\uc740 \ud55c\ub3d9\uc548 \uacf5\ud3ec\uc5d0 \uc9c0\ubc30\ub429\ub2c8\ub2e4.",B.q)
B.V8=new A.l(2001,9,14,"\ucf58\uc194 \ucd9c\uc2dc","\ub2cc\ud150\ub3c4 \uac8c\uc784\ud050\ube0c, \uc77c\ubcf8 \ubc1c\ub9e4","\ub2cc\ud150\ub3c4\uc758 \uc0c8 \uac70\uce58\ud615 \uac8c\uc784\uae30\uac00 \uc77c\ubcf8\uc5d0\uc11c \ucd9c\uc2dc\ub410\ub2e4. \uc18c\ub2c8\xb7MS\uc640\uc758 \ucf58\uc194 3\ud30c\uc804\uc774 \ub2ec\uc544\uc624\ub978\ub2e4.","3\ud30c\uc804\uc758 \uc2b9\uc790\ub294 \uae30\uae30 \uc131\ub2a5\ub9cc\uc73c\ub85c \uac08\ub9ac\uc9c0 \uc54a\uc2b5\ub2c8\ub2e4.",B.x)
B.W2=new A.l(2001,9,17,"\uc99d\uc2dc \uc7ac\uac1c\uc7a5","9\xb711 \ub2f7\uc0c8 \ub9cc\uc5d0 \ub274\uc695\uc99d\uc2dc \uc7ac\uac1c\uc7a5, \uae09\ub77d","\ub098\ud758\uac04 \uba48\ucdc4\ub358 \uc99d\uc2dc\uac00 \ub2e4\uc2dc \uc5f4\ub9ac\uc790 \uc8fc\uac00\uac00 \ud06c\uac8c \ub5a8\uc5b4\uc84c\ub2e4. \uacf5\ud3ec\uac00 \uc2dc\uc7a5\uc744 \uc9d3\ub20c\ub800\ub2e4.","\ud328\ub2c9\uc758 \ud55c\ubcf5\ud310\uc5d0\uc11c \uc6d0\uce59\uc744 \uc9c0\ud0a4\uae30\uac00 \uac00\uc7a5 \uc5b4\ub835\uc2b5\ub2c8\ub2e4.",B.q)
B.Yh=new A.l(2001,9,21,"\ub9e4\uac01 \ud569\uc758","\ub300\uc6b0\uc790\ub3d9\ucc28, GM\uc5d0 \ub9e4\uac01 \uc591\ud574\uac01\uc11c","\ubd80\ub3c4\ub09c \ub300\uc6b0\uc790\ub3d9\ucc28\uac00 \ubbf8\uad6d GM\uc5d0 \ud314\ub9ac\ub294 \uc808\ucc28\ub97c \uc2dc\uc791\ud588\ub2e4. \uc7ac\ubc8c \uad6c\uc870\uc870\uc815\uc758 \ud55c \ub9e4\ub4ed\uc774 \uc9c0\uc5b4\uc84c\ub2e4.","\uc704\uae30 \uae30\uc5c5\uc758 \uc8fc\uc778\uc774 \ubc14\ub00c\uba74 \ud310\uc774 \ub9ac\uc14b\ub429\ub2c8\ub2e4.",B.p)
B.Y9=new A.l(2001,10,1,"\ud569\uc791 \ucd9c\ubc94","\uc18c\ub2c8-\uc5d0\ub9ad\uc2a8 \ud734\ub300\ud3f0 \ud569\uc791\uc0ac \ucd9c\ubc94","\uc18c\ub2c8\uc640 \uc5d0\ub9ad\uc2a8\uc774 \uc808\ubc18\uc529 \ud22c\uc790\ud55c \ud734\ub300\ud3f0 \ud68c\uc0ac\uac00 \uc601\uc5c5\uc744 \uc2dc\uc791\ud588\ub2e4. \ubaa8\ubc14\uc77c \uacbd\uc7c1\uc5d0 \uc0c8 \uc120\uc218\uac00 \ub4f1\uc7a5\ud588\ub2e4.","\ub3d9\ub9f9\uc73c\ub85c \uc57d\uc810\uc744 \uba54\uc6b0\ub294 \uc804\ub7b5, \uc131\ud328\ub294 \uc2e4\ud589\uc5d0 \ub2ec\ub838\uc2b5\ub2c8\ub2e4.",B.x)
B.Zv=new A.l(2001,10,4,"\uc5ec\uac1d\uae30 \ucc38\uc0ac","\uc2dc\ubca0\ub9ac\uc544\ud56d\uacf5 \uc5ec\uac1d\uae30, \ud751\ud574\uc11c \ucd94\ub77d","\ud6c8\ub828 \uc911\uc774\ub358 \ubbf8\uc0ac\uc77c\uc5d0 \ub9de\uc544 \uc5ec\uac1d\uae30\uac00 \ucd94\ub77d\ud574 \uc2b9\uac1d\uacfc \uc2b9\ubb34\uc6d0 78\uba85\uc774 \uc228\uc84c\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uc804\ud569\ub2c8\ub2e4.",B.q)
B.Xg=new A.l(2001,10,7,"\uc804\uc7c1 \uac1c\uc2dc","\ubbf8\uad6d\xb7\uc601\uad6d, \uc544\ud504\uac00\ub2c8\uc2a4\ud0c4 \uacf5\uc2b5 \uc2dc\uc791","9\xb711\uc758 \ubc30\ud6c4\ub97c \uaca8\ub0e5\ud574 \uc544\ud504\uac00\ub2c8\uc2a4\ud0c4 \uacf5\uc2b5\uc774 \uc2dc\uc791\ub410\ub2e4. '\ud14c\ub7ec\uc640\uc758 \uc804\uc7c1'\uc774 \ub9c9\uc744 \uc62c\ub838\ub2e4.","\uc804\uc7c1\uc740 \uc720\uac00\uc640 \ubc29\uc704\xb7\uc548\uc804 \uad00\ub828 \uc0b0\uc5c5\uc744 \ud754\ub4ed\ub2c8\ub2e4.",B.q)
B.X9=new A.l(2001,10,12,"\ud30c\uc0b0 \uc2e0\uccad","\uc989\uc11d\uce74\uba54\ub77c \uba85\uac00 \ud3f4\ub77c\ub85c\uc774\ub4dc, \ud30c\uc0b0\ubcf4\ud638 \uc2e0\uccad","\ub514\uc9c0\ud138\uce74\uba54\ub77c \ubb3c\uacb0\uc5d0 \ubc00\ub9b0 \ud3f4\ub77c\ub85c\uc774\ub4dc\uac00 \ud30c\uc0b0\ubcf4\ud638\ub97c \uc2e0\uccad\ud588\ub2e4. \ubcc0\ud654\uc5d0 \ub2a6\uc740 \ub300\uac00\ub294 \ucef8\ub2e4.","\uc798\ub098\uac00\ub358 \ube0c\ub79c\ub4dc\ub3c4 \uae30\uc220 \uc804\ud658\uc744 \ub193\uce58\uba74 \ubb34\ub108\uc9d1\ub2c8\ub2e4.",B.q)
B.Vq=new A.l(2001,10,23,"\uc81c\ud488 \uacf5\uac1c","\uc560\ud50c, \uc544\uc774\ud31f \uacf5\uac1c","'\uc8fc\uba38\ub2c8 \uc18d \ucc9c \uace1'\uc744 \ub0b4\uac74 \uc18c\ud615 MP3 \ud50c\ub808\uc774\uc5b4\uac00 \ub4f1\uc7a5\ud588\ub2e4. \uc560\ud50c\uc774 \uc74c\uc545 \uae30\uae30\ub85c \uc601\uc5ed\uc744 \ub113\ud614\ub2e4.","\uc7a5\uae30 \ubcf5\ub9ac\uc640 \ub2e8\uae30 \uc0dd\uc874\uc758 \uade0\ud615\uc744 \uc0dd\uac01\ud558\uc138\uc694.",B.x)
B.V4=new A.l(2001,10,25,"\uc6b4\uc601\uccb4\uc81c","\ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8, \uc708\ub3c4\uc6b0 XP \ucd9c\uc2dc","\uc548\uc815\uc131\uacfc \ub514\uc790\uc778\uc744 \uc55e\uc138\uc6b4 \uc0c8 \uc708\ub3c4\uc6b0\uac00 \uc815\uc2dd \ucd9c\uc2dc\ub410\ub2e4. \uc624\ub7ab\ub3d9\uc548 PC\uc758 \ud45c\uc900\uc73c\ub85c \uc790\ub9ac \uc7a1\ub294\ub2e4.","\ud45c\uc900\uc744 \uc954 \uae30\uc5c5\uc740 \uc624\ub798 \ud604\uae08\uc744 \ub9cc\ub4ed\ub2c8\ub2e4.",B.x)
B.ZY=new A.l(2001,10,26,"\uc548\ubcf4 \uc785\ubc95","\ubd80\uc2dc, \uc560\uad6d\ubc95 \uc11c\uba85\u2026 \uac10\uc2dc \uad8c\ud55c \ud655\ub300","\ud14c\ub7ec \ub300\uc751\uc744 \uba85\ubd84\uc73c\ub85c \uc815\ubd80\uc758 \uac10\uc2dc \uad8c\ud55c\uc774 \ud06c\uac8c \ub298\uc5c8\ub2e4. \uc548\ubcf4\uc640 \uc790\uc720\uc758 \uade0\ud615 \ub17c\uc7c1\uc774 \uc2dc\uc791\ub410\ub2e4.","\uc704\uae30 \ub4a4\uc5d4 \uaddc\uc81c\uc640 \uac10\uc2dc\uac00 \ub530\ub77c\uc635\ub2c8\ub2e4.",B.q)
B.WC=new A.l(2001,11,2,"\uc560\ub2c8\uba54\uc774\uc158","\ud53d\uc0ac '\ubaac\uc2a4\ud130 \uc8fc\uc2dd\ud68c\uc0ac' \uac1c\ubd09","\ud53d\uc0ac\uc758 \uc0c8 3D \uc560\ub2c8\uba54\uc774\uc158\uc774 \uac1c\ubd09\ud574 \ud765\ud589\uc5d0 \uc131\uacf5\ud588\ub2e4. \uc560\ub2c8\uba54\uc774\uc158 \uc0b0\uc5c5\uc758 \uc8fc\ub3c4\uad8c \uacbd\uc7c1\uc774 \ub728\uac81\ub2e4.","\ud788\ud2b8 \ucf58\ud150\uce20\ub294 \ub450\uace0\ub450\uace0 \ub3c8\uc744 \ubc84\ub294 \uc9c0\uc2dd\uc7ac\uc0b0\uc785\ub2c8\ub2e4.",B.x)
B.ZM=new A.l(2001,11,12,"\uc5ec\uac1d\uae30 \ucd94\ub77d","\uc544\uba54\ub9ac\uce78\ud56d\uacf5 587\ud3b8, \ub274\uc695\uc11c \ucd94\ub77d","\uc774\ub959 \uc9c1\ud6c4 \uc5ec\uac1d\uae30\uac00 \uc8fc\ud0dd\uac00\uc5d0 \ucd94\ub77d\ud574 265\uba85\uc774 \uc228\uc84c\ub2e4. 9\xb711 \ub450 \ub2ec \ub9cc\uc758 \ucc38\uc0ac\uc600\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uc804\ud569\ub2c8\ub2e4.",B.q)
B.YR=new A.l(2001,11,13,"\uc5ec\ub2f9 \ucd1d\uc7ac \uc0ac\ud1f4","\uae40\ub300\uc911 \ub300\ud1b5\ub839, \uc5ec\ub2f9 \ucd1d\uc7ac\uc9c1 \uc0ac\ud1f4","\uac01\uc885 \uc545\uc7ac \uc18d\uc5d0 \ub300\ud1b5\ub839\uc774 \uc0c8\ucc9c\ub144\ubbfc\uc8fc\ub2f9 \ucd1d\uc7ac\uc9c1\uc5d0\uc11c \ubb3c\ub7ec\ub0ac\ub2e4. \uc784\uae30 \ud6c4\ubc18 \uad6d\uc815 \ub3d9\ub825\uc774 \ud754\ub4e4\ub9b0\ub2e4.","\uc815\uce58 \ubd88\ud655\uc2e4\uc131\uc740 \uc815\ucc45 \uad00\ub828\uc8fc\uc5d0 \uba3c\uc800 \ubc18\uc601\ub429\ub2c8\ub2e4.",B.q)
B.X4=new A.l(2001,11,15,"\ucf58\uc194 \uc9c4\ucd9c","\ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8, \uc5d1\uc2a4\ubc15\uc2a4 \ucd9c\uc2dc","\uc18c\ud504\ud2b8\uc6e8\uc5b4 \uac15\uc790\uac00 \uac8c\uc784\uae30 \uc2dc\uc7a5\uc5d0 \ub6f0\uc5b4\ub4e4\uc5c8\ub2e4. '\ud5e4\uc77c\ub85c'\ub97c \uc55e\uc138\uc6cc \uac70\uc2e4 \uc804\uc7c1\uc5d0 \ucc38\uc804\ud588\ub2e4.","\ubcf8\uc5c5 \ubc16 \ub3c4\uc804\uc740 \uc131\uacf5\ud558\uba74 \uc0c8 \uc131\uc7a5 \ucd95\uc774 \ub429\ub2c8\ub2e4.",B.x)
B.WD=new A.l(2001,11,16,"\uc601\ud654 \uac1c\ubd09","'\ud574\ub9ac \ud3ec\ud130\uc640 \ub9c8\ubc95\uc0ac\uc758 \ub3cc' \uac1c\ubd09","\uc138\uacc4\uc801 \ubca0\uc2a4\ud2b8\uc140\ub7ec\uac00 \uc601\ud654\ub85c \ub098\uc640 \ud765\ud589 \ub3cc\ud48d\uc744 \uc77c\uc73c\ucf30\ub2e4. \ub300\ud615 \ud504\ub79c\ucc28\uc774\uc988 \uc2dc\ub300\uac00 \uc5f4\ub838\ub2e4.","\ud558\ub098\uc758 \uc774\uc57c\uae30\uac00 \ucc45\xb7\uc601\ud654\xb7\uc0c1\ud488\uc73c\ub85c \ud655\uc7a5\ub429\ub2c8\ub2e4.",B.x)
B.Xy=new A.l(2001,11,25,"\uae30\uad6c \ucd9c\ubc94","\uad6d\uac00\uc778\uad8c\uc704\uc6d0\ud68c \uacf5\uc2dd \ucd9c\ubc94","\ub3c5\ub9bd \uc778\uad8c \uae30\uad6c\uac00 \ubb38\uc744 \uc5f4\uc5c8\ub2e4. \uc778\uad8c\uc744 \uac10\uc2dc\ud558\ub294 \uc81c\ub3c4\uc801 \uc7a5\uce58\uac00 \ub9c8\ub828\ub410\ub2e4.","\uc81c\ub3c4\uc758 \uc131\uc219\uc740 \uc0ac\ud68c\uc758 \uc2e0\ub8b0 \uc790\ubcf8\uc744 \uc313\uc2b5\ub2c8\ub2e4.",B.p)
B.a_A=new A.l(2001,12,1,"\uc6d4\ub4dc\ucef5 \uc870\ucd94\ucca8","2002 \ud55c\uc77c\uc6d4\ub4dc\ucef5 \uc870\ucd94\ucca8, \ud55c\uad6d D\uc870","\uac1c\ucd5c\uad6d \ud55c\uad6d\uc774 \ubbf8\uad6d\xb7\ud3ec\ub974\ud22c\uac08\xb7\ud3f4\ub780\ub4dc\uc640 \ud55c \uc870\uc5d0 \ubb36\uc600\ub2e4. \uc548\ubc29 \uc6d4\ub4dc\ucef5\uc774 6\uac1c\uc6d4 \uc55e\uc73c\ub85c \ub2e4\uac00\uc654\ub2e4.","\uad6d\uac00\uc801 \uc774\ubca4\ud2b8\ub294 \uc18c\ube44\uc640 \ubd84\uc704\uae30\ub97c \ub04c\uc5b4\uc62c\ub9bd\ub2c8\ub2e4.",B.p)
B.Ug=new A.l(2001,12,2,"\ucd08\ub300\ud615 \ud30c\uc0b0","\uc5d4\ub860, \ud30c\uc0b0\ubcf4\ud638 \uc2e0\uccad\u2026 \u7f8e \ucd5c\ub300 \uaddc\ubaa8","\ud68c\uacc4 \ubd80\uc815\uc774 \ub4dc\ub7ec\ub09c \uc5d0\ub108\uc9c0 \ub300\uae30\uc5c5 \uc5d4\ub860\uc774 \ubb34\ub108\uc84c\ub2e4. \uae30\uc5c5 \uc2e0\ub8b0\uc640 \ud68c\uacc4 \uac10\ub3c5\uc5d0 \uacbd\uc885\uc774 \uc6b8\ub838\ub2e4.","\uc22b\uc790\ub97c \ubbff\uc9c0 \ubabb\ud558\uba74 \ud22c\uc790\ub3c4 \uc5c6\uc2b5\ub2c8\ub2e4. \ud68c\uacc4\ub97c \uc758\uc2ec\ud558\uc138\uc694.",B.q)
B.Y0=new A.l(2001,12,3,"\uc2e0\uc81c\ud488","\ub518 \ucf00\uc774\uba3c, \uc774\ub3d9\uc218\ub2e8 '\uc138\uadf8\uc6e8\uc774' \uacf5\uac1c","\uc790\uc774\ub85c\ub85c \uade0\ud615\uc744 \uc7a1\ub294 1\uc778\uc6a9 \uc804\ub3d9 \uc774\ub3d9\uc218\ub2e8\uc774 \uacf5\uac1c\ub410\ub2e4. \uc694\ub780\ud55c \uae30\ub300 \uc18d\uc5d0 \ub4f1\uc7a5\ud588\ub2e4.","\uacfc\ub300\uad11\uace0\uc640 \uc9c4\uc9dc \ud601\uc2e0\uc744 \uac00\ub824\ub0b4\ub294 \ub208\uc774 \ud544\uc694\ud569\ub2c8\ub2e4.",B.x)
B.Ze=new A.l(2001,12,11,"\uc138\uacc4\ubb34\uc5ed","\uc911\uad6d, WTO \uc815\uc2dd \uac00\uc785","15\ub144 \ud611\uc0c1 \ub05d\uc5d0 \uc911\uad6d\uc774 \uc138\uacc4\ubb34\uc5ed\uae30\uad6c\uc758 143\ubc88\uc9f8 \ud68c\uc6d0\uc774 \ub410\ub2e4. '\uc138\uacc4\uc758 \uacf5\uc7a5' \uc2dc\ub300\uac00 \ubcf8\uaca9\ud654\ud55c\ub2e4.","\uac70\ub300 \uc2dc\uc7a5\uc758 \uac1c\ubc29\uc740 \uc218\uc2ed \ub144\uc758 \ud310\uc744 \ubc14\uafc9\ub2c8\ub2e4.",B.p)
B.V7=new A.l(2001,12,15,"\ubcf5\uc6d0 \uc644\ub8cc","\uc774\ud0c8\ub9ac\uc544 \ud53c\uc0ac\uc758 \uc0ac\ud0d1, \uc7ac\uac1c\uc7a5","\uae30\uc6b8\uae30\ub97c \ubc14\ub85c\uc7a1\ub294 \ubcf4\uac15 \uacf5\uc0ac\ub97c \ub9c8\uce5c \ud53c\uc0ac\uc758 \uc0ac\ud0d1\uc774 \ub2e4\uc2dc \ubb38\uc744 \uc5f4\uc5c8\ub2e4.","\uc624\ub798\ub41c \uc790\uc0b0\ub3c4 \uc190\ubcf4\uba74 \ub2e4\uc2dc \uac00\uce58\ub97c \ub0c5\ub2c8\ub2e4.",B.J)
B.X5=new A.l(2001,12,19,"\uc601\ud654 \uac1c\ubd09","'\ubc18\uc9c0\uc758 \uc81c\uc655: \ubc18\uc9c0 \uc6d0\uc815\ub300' \uac1c\ubd09","\ub300\uc791 \ud310\ud0c0\uc9c0 3\ubd80\uc791\uc758 \uccab \ud3b8\uc774 \uac1c\ubd09\ud574 \uc138\uacc4\uc801 \ud765\ud589\uc744 \uc608\uace0\ud588\ub2e4. \ub300\ud615 \ud504\ub79c\ucc28\uc774\uc988 \uacbd\uc7c1\uc774 \ub728\uac81\ub2e4.","\uc7a5\uae30 \uc2dc\ub9ac\uc988\ub294 \uc5ec\ub7ec \ud574\uc5d0 \uac78\uce5c \uc218\uc775 \uc5d4\uc9c4\uc785\ub2c8\ub2e4.",B.x)
B.YS=new A.l(2001,12,20,"\uad6d\uac00 \ubd80\ub3c4","\uc544\ub974\ud5e8\ud2f0\ub098 \uacbd\uc81c\uc704\uae30\u2026 \ub300\ud1b5\ub839 \uc0ac\uc784","\uc608\uae08 \uc778\ucd9c \uc81c\ud55c\uc5d0 \uc131\ub09c \uc2dc\uc704 \uc18d\uc5d0 \ub300\ud1b5\ub839\uc774 \ubb3c\ub7ec\ub0ac\uace0, \uace7 \uc0ac\uc0c1 \ucd5c\ub300 \uaddc\ubaa8\uc758 \uad6d\uac00 \ubd80\ub3c4\uac00 \uc120\uc5b8\ub410\ub2e4.","\uc2e0\ud765\uad6d \uc704\uae30\ub294 \uc21c\uc2dd\uac04\uc5d0 \uad6d\uacbd\uc744 \ub118\uc5b4 \ubc88\uc9d1\ub2c8\ub2e4.",B.q)
B.UQ=new A.l(2001,12,22,"\uacfc\ub3c4\uc815\ubd80","\uc544\ud504\uac00\ub2c8\uc2a4\ud0c4 \uce74\ub974\uc790\uc774 \uacfc\ub3c4\uc815\ubd80 \ucd9c\ubc94","\ud0c8\ub808\ubc18\uc774 \ubb34\ub108\uc9c4 \ub4a4 \ud558\ubbf8\ub4dc \uce74\ub974\uc790\uc774\uac00 \uc774\ub044\ub294 \uacfc\ub3c4\uc815\ubd80\uac00 \ub4e4\uc5b4\uc130\ub2e4. \uc7ac\uac74\uc758 \uccab\ubc1c\uc744 \ub5d0\ub2e4.","\ud63c\ub780 \ub4a4\uc5d4 \uc7ac\uac74 \uc218\uc694\uac00 \ub530\ub77c\uc635\ub2c8\ub2e4.",B.J)
B.XL=new A.l(2002,1,1,"\uc720\ub85c\ud654 \ucd9c\ubc94","\uc720\ub85c\ud654 \ud604\uae08, 12\uac1c\uad6d\uc11c \ud1b5\uc6a9 \uc2dc\uc791","\uc720\ub7fd 12\uac1c\uad6d\uc774 \uac19\uc740 \uc9c0\ud3d0\uc640 \ub3d9\uc804\uc744 \uc4f0\uae30 \uc2dc\uc791\ud588\ub2e4. \uc138\uacc4 \ubb34\uc5ed\uacfc \ud658\uc728 \uc9c0\ud615\uc774 \ud06c\uac8c \ubc14\ub010\ub2e4.","\ub2e8\uc77c\ud1b5\ud654\ub294 \uc720\ub7fd \uc790\uc0b0\uc758 \uc0c1\uad00\uad00\uacc4\ub97c \ubc14\uafc9\ub2c8\ub2e4. \ud658\uc704\ud5d8 \ub178\ucd9c\uc744 \ub2e4\uc2dc \uc810\uac80\ud558\uc138\uc694.",B.p)
B.a_f=new A.l(2002,1,7,"\uc560\ud50c \uc2e0\uc81c\ud488","\uc560\ud50c, \ud3c9\uba74 LCD \uc544\uc774\ub9e5 G4 \uacf5\uac1c","\uc7a1\uc2a4\uac00 \ub9e5\uc6d4\ub4dc\uc5d0\uc11c \ubc1b\uce68\ub300\uc5d0 \ub72c \uc561\uc815\ud654\uba74\uc758 \uc0c8 \uc544\uc774\ub9e5\uc744 \uc120\ubcf4\uc600\ub2e4. PC\uc758 CRT \uc2dc\ub300\uac00 \uc800\ubb38\ub2e4.","\ub514\uc2a4\ud50c\ub808\uc774 \uc804\ud658\uc740 \ubd80\ud488 \uacf5\uae09\ub9dd\uc758 \uc8fc\ub3c4\uad8c\uc744 \ubc14\uafc9\ub2c8\ub2e4. \ud328\ub110\xb7\uc18c\uc7ac\uc8fc\ub97c \ud568\uaed8 \ubcf4\uc138\uc694.",B.x)
B.Zo=new A.l(2002,1,28,"\uc774\ub3d9\ud1b5\uc2e0","SK\ud154\ub808\ucf64, \uc138\uacc4 \uccab EV-DO \uc0c1\uc6a9\ud654","SK\ud154\ub808\ucf64\uc774 \uc778\ucc9c\uc5d0\uc11c \uc138\uacc4 \ucd5c\ucd08\ub85c \uace0\uc18d \ubb34\uc120\ub370\uc774\ud130 \uc11c\ube44\uc2a4\ub97c \uc5f4\uc5c8\ub2e4. \ud734\ub300\ud3f0\uc774 \uc74c\uc131\uc5d0\uc11c \ub370\uc774\ud130\ub85c \ub118\uc5b4\uac04\ub2e4.","\ud55c\uad6d \ud1b5\uc2e0\uc8fc\uac00 \ub370\uc774\ud130 \uc2dc\ub300\uc758 \uc120\ub450\uc5d0 \uc130\uc2b5\ub2c8\ub2e4. \uc7a5\ube44\xb7\ucf58\ud150\uce20 \ud6c4\ubc29\ub3c4 \uc0b4\ud53c\uc138\uc694.",B.p)
B.Z9=new A.l(2002,1,29,"\ubbf8\uad6d \uc678\uad50","\ubd80\uc2dc, \ubd81\ud55c\xb7\uc774\ub77c\ud06c\xb7\uc774\ub780 '\uc545\uc758 \ucd95' \uaddc\uc815","\ubd80\uc2dc \ub300\ud1b5\ub839\uc774 \uc5f0\ub450\uad50\uc11c\uc5d0\uc11c \uc138 \ub098\ub77c\ub97c '\uc545\uc758 \ucd95'\uc73c\ub85c \uc9c0\ubaa9\ud588\ub2e4. \uc9c0\uc815\ud559 \uae34\uc7a5\uc774 \uc2dc\uc7a5\uc758 \ubcc0\uc218\ub85c \ub5a0\uc624\ub978\ub2e4.","\uc9c0\uc815\ud559 \ub9ac\uc2a4\ud06c\ub294 \uc720\uac00\uc640 \uc548\uc804\uc790\uc0b0\uc5d0 \ud30c\uc7a5\uc744 \uc90d\ub2c8\ub2e4. \ud3ec\ud2b8\ud3f4\ub9ac\uc624 \ubc29\uc5b4\ub825\uc744 \uc810\uac80\ud558\uc138\uc694.",B.q)
B.a_b=new A.l(2002,2,22,"\ucf58\uc194 \uc804\uc7c1","MS \uc5d1\uc2a4\ubc15\uc2a4, \uc77c\ubcf8 \uc2dc\uc7a5 \ucd9c\uc2dc","\ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8\uac00 \uac8c\uc784\uae30 \uc5d1\uc2a4\ubc15\uc2a4\ub97c \uc77c\ubcf8\uc5d0 \ub0b4\ub1a8\ub2e4. \uc18c\ub2c8\xb7\ub2cc\ud150\ub3c4\uc758 \uc548\ubc29\uc5d0 \ub3c4\uc804\uc7a5\uc744 \ub358\uc84c\ub2e4.","\ucf58\uc194 \uacbd\uc7c1 \uc2ec\ud654\ub294 \ubc18\ub3c4\uccb4\xb7\ubd80\ud488 \uc218\uc694\ub85c \uc774\uc5b4\uc9d1\ub2c8\ub2e4. \uacf5\uae09\uc0ac\ub97c \ub530\ub77c\uac00 \ubcf4\uc138\uc694.",B.x)
B.Zx=new A.l(2002,2,25,"\ub178\ub3d9","\ucca0\ub3c4\xb7\uac00\uc2a4\xb7\ubc1c\uc804 \uc5f0\ub300\ud30c\uc5c5 \ub3cc\uc785","\uacf5\uae30\uc5c5 \ubbfc\uc601\ud654\uc5d0 \ubc18\ub300\ud558\uba70 \ucca0\ub3c4\xb7\uac00\uc2a4\xb7\ubc1c\uc804 \ub178\uc870\uac00 \ub3d9\uc2dc \ud30c\uc5c5\uc5d0 \ub4e4\uc5b4\uac14\ub2e4. \ubb3c\ub958\uc640 \uc5d0\ub108\uc9c0 \uacf5\uae09\uc5d0 \ucc28\uc9c8\uc774 \ube5a\uc5b4\uc9c4\ub2e4.","\ub300\uaddc\ubaa8 \ud30c\uc5c5\uc740 \ubb3c\ub958\xb7\uc5d0\ub108\uc9c0 \ube44\uc6a9\uc744 \uc790\uadf9\ud569\ub2c8\ub2e4. \uad00\ub828 \uc5c5\uc885\uc758 \ub2e8\uae30 \ucda9\uaca9\uc744 \uc0b4\ud53c\uc138\uc694.",B.q)
B.Vk=new A.l(2002,3,3,"\ubaa8\ud130\uc2a4\ud3ec\uce20","\ud1a0\uc694\ud0c0, F1 \ub370\ubdd4\uc804\uc11c \uccab \ud3ec\uc778\ud2b8","\ud1a0\uc694\ud0c0\uac00 \ud638\uc8fc GP\ub85c F1\uc5d0 \ub370\ubdd4\ud574 \uccab \uacbd\uae30\ubd80\ud130 \uc785\uc0c1\ud588\ub2e4. \ube0c\ub79c\ub4dc \uace0\uae09\ud654\uc640 \uae00\ub85c\ubc8c \ud655\uc7a5 \uc758\uc9c0\ub97c \ub4dc\ub7ec\ub0c8\ub2e4.","\uc644\uc131\ucc28\uc758 \ube0c\ub79c\ub4dc \ud22c\uc790\ub294 \uc7a5\uae30 \uc131\uc7a5 \uc2e0\ud638\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4. \ubcf8\uc5c5 \uc2e4\uc801\uacfc \ud568\uaed8 \ubcf4\uc138\uc694.",B.p)
B.XS=new A.l(2002,3,15,"\uc0ac\uba85 \ubcc0\uacbd","\ud3ec\ud56d\uc81c\ucca0, \uc0ac\uba85\uc744 'POSCO'\ub85c \ubcc0\uacbd","\ud3ec\ud56d\uc885\ud569\uc81c\ucca0\uc774 \ud68c\uc0ac \uc774\ub984\uc744 \ud3ec\uc2a4\ucf54\ub85c \ubc14\uafe8\ub2e4. \ubbfc\uc601\ud654 \uc774\ud6c4 \uae00\ub85c\ubc8c \ucca0\uac15\uc0ac\ub85c\uc758 \ubcc0\uc2e0\uc744 \uc54c\ub9b0\ub2e4.","\ucca0\uac15\uc740 \uacbd\uae30 \uc0ac\uc774\ud074\uc758 \ubc14\ub85c\ubbf8\ud130\uc785\ub2c8\ub2e4. \uc804\ubc29 \uc0b0\uc5c5\uc758 \uc218\uc694\ub97c \ud568\uaed8 \ud655\uc778\ud558\uc138\uc694.",B.p)
B.XU=new A.l(2002,4,15,"\ud56d\uacf5 \uc0ac\uace0","\uc911\uad6d\uad6d\uc81c\ud56d\uacf5 \uc5ec\uac1d\uae30, \uae40\ud574 \uc57c\uc0b0\uc5d0 \ucd94\ub77d","\ubca0\uc774\uc9d5\ubc1c \uc5ec\uac1d\uae30\uac00 \uae40\ud574 \uc778\uadfc \uc57c\uc0b0\uc5d0 \ucd94\ub77d\ud574 \ub2e4\uc218\uac00 \uc228\uc84c\ub2e4. \uc545\ucc9c\ud6c4 \uc18d \uc811\uadfc \uc911 \uc0ac\uace0\uac00 \ub0ac\ub2e4.","\uc548\uc804 \uc774\uc288\ub294 \ud56d\uacf5\xb7\uc5ec\ud589 \uc2ec\ub9ac\uc5d0 \ub2e8\uae30 \ucda9\uaca9\uc744 \uc90d\ub2c8\ub2e4. \uc0ac\uc2e4\uc744 \ud655\uc778\ud55c \ub4a4 \ud310\ub2e8\ud558\uc138\uc694.",B.q)
B.a_r=new A.l(2002,5,3,"\ucf58\uc194 \uc804\uc7c1","\ub2cc\ud150\ub3c4 \uac8c\uc784\ud050\ube0c, \uc720\ub7fd \ucd9c\uc2dc","\ub2cc\ud150\ub3c4\uc758 \uc2e0\ud615 \uac8c\uc784\uae30\uac00 \uc720\ub7fd\uc5d0 \uc0c1\ub959\ud588\ub2e4. \uc18c\ub2c8 PS2, MS \uc5d1\uc2a4\ubc15\uc2a4\uc640\uc758 3\ud30c\uc804\uc774 \ubcf8\uaca9\ud654\ud55c\ub2e4.","\uac8c\uc784 \ud558\ub4dc\uc6e8\uc5b4 \uacbd\uc7c1\uc740 \ubc18\ub3c4\uccb4\xb7\uc800\uc7a5\uc7a5\uce58 \uc218\uc694\ub97c \ud0a4\uc6c1\ub2c8\ub2e4. \ubd80\ud488\uc8fc\ub97c \uc0b4\ud53c\uc138\uc694.",B.x)
B.W8=new A.l(2002,5,20,"\uc2e0\uc0dd \ub3c5\ub9bd\uad6d","\ub3d9\ud2f0\ubaa8\ub974, \uc815\uc2dd \ub3c5\ub9bd\uad6d\uc73c\ub85c \ucd9c\ubc94","\uc778\ub3c4\ub124\uc2dc\uc544 \uc9c0\ubc30\uc640 \uc720\uc5d4 \uacfc\ub3c4\ud1b5\uce58\ub97c \uac70\uccd0 \ub3d9\ud2f0\ubaa8\ub974\uac00 \ub3c5\ub9bd\ud588\ub2e4. 21\uc138\uae30 \uccab \ub3c5\ub9bd\uad6d\uc774 \ud0c4\uc0dd\ud588\ub2e4.","\uc2e0\ud765\uad6d\uc758 \ub4f1\uc7a5\uc740 \uc7a5\uae30 \ud14c\ub9c8\uc785\ub2c8\ub2e4. \uc131\uae09\ud55c \uae30\ub300\ub294 \uacbd\uacc4\ud558\uc138\uc694.",B.p)
B.Y_=new A.l(2002,5,31,"\uad6d\uac00 \uc774\ubca4\ud2b8","\ud55c\xb7\uc77c \uc6d4\ub4dc\ucef5\uc774 \uac1c\ub9c9\ud588\ub2e4","\ud55c\uad6d\uacfc \uc77c\ubcf8\uc774 \uacf5\ub3d9 \uac1c\ucd5c\ud55c \uc6d4\ub4dc\ucef5\uc774 \ub9c9\uc744 \uc62c\ub838\ub2e4. \uac70\ub9ac \uc751\uc6d0\uacfc \uc18c\ube44 \uc2ec\ub9ac\uac00 \ub2ec\uc544\uc624\ub978\ub2e4.","\ucd95\uc81c \ubd84\uc704\uae30\uc640 \uc2e4\uc801\uc740 \ub2e4\ub985\ub2c8\ub2e4. \uad6d\ub0b4 \uc18c\ube44\xb7\uc720\ud1b5\uc8fc\ub294 \uc625\uc11d\uc744 \uac00\ub9ac\uc138\uc694.",B.p)
B.Xc=new A.l(2002,6,13,"\uc0ac\ud68c \uc774\uc288","\ubbf8\uad70 \uc7a5\uac11\ucc28\uc5d0 \uc5ec\uc911\uc0dd \ub450 \uba85 \uc0ac\ub9dd","\ud6c8\ub828 \uc911\uc774\ub358 \uc8fc\ud55c\ubbf8\uad70 \uc7a5\uac11\ucc28\uc5d0 \uc5ec\uc911\uc0dd \ub450 \uba85\uc774 \ubaa9\uc228\uc744 \uc783\uc5c8\ub2e4. \ub300\uaddc\ubaa8 \ucd94\ubaa8 \ubb3c\uacb0\uacfc SOFA \uac1c\uc815 \uc5ec\ub860\uc774 \ucee4\uc9c4\ub2e4.","\uc0ac\ud68c \uac08\ub4f1\uc740 \uc815\uce58\xb7\uc678\uad50 \uc77c\uc815\uc744 \ud754\ub4ed\ub2c8\ub2e4. \uc5ec\ub860\uc758 \ud750\ub984\uc744 \uc9c0\ucf1c\ubcf4\uc138\uc694.",B.q)
B.VM=new A.l(2002,6,15,"\ud68c\uacc4 \uc2a4\uce94\ub4e4","\uc544\uc11c \uc564\ub354\uc2a8, \uc0ac\ubc95\ubc29\ud574 \uc720\uc8c4 \ud3c9\uacb0","\uc5d4\ub860 \uc0ac\ud0dc\ub85c \ud68c\uacc4\ubc95\uc778 \uc544\uc11c \uc564\ub354\uc2a8\uc774 \ubb38\uc11c \ud30c\uae30\ub85c \uc720\uc8c4\ub97c \ubc1b\uc558\ub2e4. 5\ub300 \ud68c\uacc4\ubc95\uc778\uc758 \ubab0\ub77d\uc774 \uc2dc\uc791\ub41c\ub2e4.","\ud68c\uacc4 \uc2e0\ub8b0 \ubd95\uad34\ub294 \uc2dc\uc7a5 \uc804\ubc18\uc758 \ud560\uc778 \uc694\uc778\uc785\ub2c8\ub2e4. \uac10\uc0ac \ud488\uc9c8\uacfc \uc9c0\ubc30\uad6c\uc870\ub97c \ubcf4\uc138\uc694.",B.q)
B.UV=new A.l(2002,6,22,"\uad6d\uac00 \uc774\ubca4\ud2b8","\ud55c\uad6d, \uc2a4\ud398\uc778 \uaebe\uace0 \uc0ac\uc0c1 \uccab 4\uac15","\ud55c\uad6d\uc774 8\uac15\uc5d0\uc11c \uc2a4\ud398\uc778\uc744 \uc2b9\ubd80\ucc28\uae30\ub85c \uc774\uae30\uace0 \ucc98\uc74c\uc73c\ub85c 4\uac15\uc5d0 \uc62c\ub790\ub2e4. \uc628 \ub098\ub77c\uac00 \ubd89\uc740 \ubb3c\uacb0\ub85c \ub4a4\ub36e\uc600\ub2e4.","\uad6d\ubbfc\uc801 \uc5f4\uae30 \uc18d\uc5d0\uc11c\ub3c4 \ub0c9\uc815\ud558\uac8c. \uad00\ub828 \uc18c\ube44\uc8fc\uc758 \uc2e4\uc81c \uc218\ud61c\ub97c \uad6c\ubd84\ud558\uc138\uc694.",B.p)
B.X8=new A.l(2002,6,25,"\ud68c\uacc4 \uc2a4\uce94\ub4e4","\uc6d4\ub4dc\ucef4, \ub300\uaddc\ubaa8 \ubd84\uc2dd\ud68c\uacc4 \ubc1c\uac01","\ud1b5\uc2e0\uacf5\ub8e1 \uc6d4\ub4dc\ucef4\uc774 \uc774\uc775\uc744 \ubd80\ud480\ub9b0 \uc0ac\uc2e4\uc774 \ub4dc\ub7ec\ub0ac\ub2e4. \ubbf8\uad6d \uc5ed\uc0ac\uc0c1 \ucd5c\ub300 \uaddc\ubaa8 \ud68c\uacc4\ubd80\uc815\uc73c\ub85c \ubc88\uc9c4\ub2e4.","\uace0\uc131\uc7a5 \ud1b5\uc2e0\uc8fc\ub3c4 \uc7a5\ubd80\ub97c \uc758\uc2ec\ud558\uc138\uc694. \ud604\uae08\ud750\ub984\uacfc \ubd80\ucc44\ub97c \uba3c\uc800 \ud655\uc778\ud558\uc138\uc694.",B.q)
B.YI=new A.l(2002,6,29,"\uc548\ubcf4","\uc11c\ud574\uc5d0\uc11c \uc81c2\uc5f0\ud3c9\ud574\uc804 \ubc1c\uc0dd","\uc6d4\ub4dc\ucef5 \uc5f4\uae30 \uc18d \uc11c\ud574\uc5d0\uc11c \ub0a8\ubd81 \ud568\uc815\uc774 \uad50\uc804\ud574 \uc6b0\ub9ac \uc7a5\ubcd1\ub4e4\uc774 \uc804\uc0ac\ud588\ub2e4. \ud55c\ubc18\ub3c4 \uae34\uc7a5\uc774 \ub2e4\uc2dc \ubd80\uac01\ub41c\ub2e4.","\uc9c0\uc815\ud559 \uae34\uc7a5\uc740 \uad6d\ub0b4 \uc99d\uc2dc\uc758 \uc0c1\uc2dc \ubcc0\uc218\uc785\ub2c8\ub2e4. \uacfc\ubbfc \ubc18\uc751\uacfc \uc2e4\uc81c \uc601\ud5a5\uc744 \uad6c\ubd84\ud558\uc138\uc694.",B.q)
B.UM=new A.l(2002,6,30,"\uc6d4\ub4dc\ucef5 \uacb0\uc0b0","\ube0c\ub77c\uc9c8, \ub3c5\uc77c \uaebe\uace0 \ud1b5\uc0b0 5\ubc88\uc9f8 \uc6b0\uc2b9","\ube0c\ub77c\uc9c8\uc774 \uacb0\uc2b9\uc5d0\uc11c \ub3c5\uc77c\uc744 2-0\uc73c\ub85c \ub20c\ub800\ub2e4. \ud55c\xb7\uc77c \uc6d4\ub4dc\ucef5\uc774 \ube0c\ub77c\uc9c8\uc758 \uc6b0\uc2b9\uc73c\ub85c \ub9c9\uc744 \ub0b4\ub9b0\ub2e4.","\ub300\ud615 \uc774\ubca4\ud2b8\uac00 \ub05d\ub098\uba74 \uc18c\ube44 \ud2b9\uc218\ub294 \ub418\ub3cc\ub9bc\uc774 \uc635\ub2c8\ub2e4. \ud53c\ud06c\uc544\uc6c3\uc744 \uacbd\uacc4\ud558\uc138\uc694.",B.p)
B.Wt=new A.l(2002,7,21,"\uae30\uc5c5 \ud30c\uc0b0","\uc6d4\ub4dc\ucef4, \uc0ac\uc0c1 \ucd5c\ub300 \uaddc\ubaa8 \ud30c\uc0b0\ubcf4\ud638 \uc2e0\uccad","\ud68c\uacc4\ubd80\uc815\uc774 \ub4dc\ub7ec\ub09c \uc6d4\ub4dc\ucef4\uc774 \ud30c\uc0b0\ubcf4\ud638\ub97c \uc2e0\uccad\ud588\ub2e4. \ub2f9\uc2dc \ubbf8\uad6d \uc5ed\uc0ac\uc0c1 \ucd5c\ub300 \uae30\uc5c5 \ud30c\uc0b0\uc774\uc5c8\ub2e4.","\ubd80\ucc44 \ub9ce\uc740 \uc131\uc7a5\uae30\uc5c5\uc740 \uc2e0\ub8b0 \uc704\uae30\uc5d0 \uae09\uaca9\ud788 \ubb34\ub108\uc9d1\ub2c8\ub2e4. \ub808\ubc84\ub9ac\uc9c0\ub97c \ud655\uc778\ud558\uc138\uc694.",B.q)
B.VO=new A.l(2002,7,30,"\uc81c\ub3c4 \ubcc0\ud654","\ubbf8\uad6d, \uc0ac\ubca0\uc778\uc2a4-\uc625\uc2ac\ub9ac\ubc95 \uc2dc\ud589","\uc787\ub2e8 \ud68c\uacc4\ubd80\uc815\uc5d0 \ub300\uc751\ud574 \uae30\uc5c5 \ud68c\uacc4\xb7\uacf5\uc2dc \ucc45\uc784\uc744 \ub300\ud3ed \uac15\ud654\ud55c \ubc95\uc774 \ubc1c\ud6a8\ub410\ub2e4. CEO\xb7CFO\uc758 \uc778\uc99d \ucc45\uc784\uc774 \ucee4\uc9c4\ub2e4.","\uaddc\uc81c \uac15\ud654\ub294 \uc2e0\ub8b0\ub97c \ud68c\ubcf5\uc2dc\ud0a4\ub418 \ube44\uc6a9\ub3c4 \ub298\ub9bd\ub2c8\ub2e4. \uc7a5\uae30\uc801\uc73c\ub860 \uc6b0\ub7c9\uc8fc\uc5d0 \uc720\ub9ac\ud569\ub2c8\ub2e4.",B.p)
B.XI=new A.l(2002,8,15,"\uc790\uc5f0\uc7ac\ud574","\uc911\ubd80 \uc720\ub7fd \ub300\ud64d\uc218, \ud504\ub77c\ud558\xb7\ub4dc\ub808\uc2a4\ub374 \uce68\uc218","\ud3ed\uc6b0\ub85c \uc5d8\ubca0\xb7\ube14\ud0c0\ubc14\uac15\uc774 \ubc94\ub78c\ud574 \uccb4\ucf54\xb7\ub3c5\uc77c \ub4f1 \uc911\ubd80 \uc720\ub7fd\uc774 \ubb3c\uc5d0 \uc7a0\uacbc\ub2e4. \ubc31 \uba85 \ub118\uac8c \uc228\uc9c0\uace0 \ud53c\ud574\uac00 \ub9c9\ub300\ud558\ub2e4.","\ub300\ud615 \uc7ac\ud574\ub294 \uc7ac\uac74 \uc218\uc694\uc640 \ubcf4\ud5d8 \uc190\uc2e4\uc744 \ub3d9\uc2dc\uc5d0 \ub0a8\uae41\ub2c8\ub2e4. \uc5c5\uc885\ubcc4\ub85c \ub098\ub220 \ubcf4\uc138\uc694.",B.q)
B.UW=new A.l(2002,8,31,"\uc790\uc5f0\uc7ac\ud574","\ud0dc\ud48d '\ub8e8\uc0ac', \ud55c\ubc18\ub3c4\ub97c \uac15\ud0c0\ud588\ub2e4","\uae30\ub85d\uc801 \ud3ed\uc6b0\ub97c \ub3d9\ubc18\ud55c \ud0dc\ud48d \ub8e8\uc0ac\uac00 \uc804\uad6d\uc744 \ud729\uc4f8\uc5b4 \ud070 \uc778\uba85\xb7\uc7ac\uc0b0 \ud53c\ud574\ub97c \ub0c8\ub2e4. \uc218\ud574 \ubcf5\uad6c\uac00 \uae09\uc120\ubb34\uac00 \ub41c\ub2e4.","\uc7ac\ud574\ub294 \ubb3c\uac00\uc640 \ubcf5\uad6c \uc608\uc0b0\uc744 \uc790\uadf9\ud569\ub2c8\ub2e4. \uac74\uc124\xb7\uc18c\uc7ac \uc218\uc694\ub97c \uc810\uac80\ud558\uc138\uc694.",B.q)
B.UU=new A.l(2002,9,17,"\ub3d9\ubd81\uc544 \uc678\uad50","\uace0\uc774\uc988\ubbf8 \ubc29\ubd81, \uccab \ubd81\xb7\uc77c \uc815\uc0c1\ud68c\ub2f4","\uace0\uc774\uc988\ubbf8 \uc77c\ubcf8 \ucd1d\ub9ac\uac00 \ud3c9\uc591\uc5d0\uc11c \uae40\uc815\uc77c\uacfc \ub9cc\ub0ac\ub2e4. \ubd81\ud55c\uc774 \uc77c\ubcf8\uc778 \ub0a9\uce58\ub97c \ucc98\uc74c \uc778\uc815\ud558\uba70 \ud30c\ubb38\uc774 \uc778\ub2e4.","\ub3d9\ubd81\uc544 \uc678\uad50 \ud574\ube59\uc740 \uc704\ud5d8\uc790\uc0b0 \uc2ec\ub9ac\uc5d0 \ud6c8\ud48d\uc785\ub2c8\ub2e4. \uc9c0\uc18d\uc131\uc740 \ub0c9\uc815\ud788 \uc9c0\ucf1c\ubcf4\uc138\uc694.",B.p)
B.WP=new A.l(2002,10,9,"\uc99d\uc2dc \ubc14\ub2e5","\ubbf8\uad6d \uc99d\uc2dc, \ub2f7\ucef4 \uc57d\uc138\uc7a5 \uc800\uc810 \uae30\ub85d","\ub2e4\uc6b0\uc640 \ub098\uc2a4\ub2e5\uc774 \uc774\ub0a0 \uc57d\uc138\uc7a5 \ucd5c\uc800\uc810\uc744 \ucc0d\uc5c8\ub2e4. \ub2f7\ucef4 \ubd95\uad34\uc640 \ud68c\uacc4\ubd80\uc815\uc758 \uacf5\ud3ec\uac00 \uc815\uc810\uc5d0 \ub2ec\ud588\ub2e4.","\uacf5\ud3ec\uac00 \uadf9\uc5d0 \ub2ec\ud560 \ub54c \uc7a5\uae30 \uc800\uc810\uc774 \ub9cc\ub4e4\uc5b4\uc9c0\uace4 \ud569\ub2c8\ub2e4. \ubd84\ud560\ub9e4\uc218 \uc6d0\uce59\uc744 \uc0c1\uae30\ud558\uc138\uc694.",B.q)
B.UK=new A.l(2002,10,12,"\ud14c\ub7ec","\uc778\ub3c4\ub124\uc2dc\uc544 \ubc1c\ub9ac\uc11c \ud3ed\ud0c4 \ud14c\ub7ec","\uad00\uad11\uc9c0 \ubc1c\ub9ac\uc758 \ub098\uc774\ud2b8\ud074\ub7fd\uc5d0\uc11c \ud3ed\ud0c4\uc774 \ud130\uc838 \uc774\ubc31\uc5ec \uba85\uc774 \uc228\uc84c\ub2e4. \ub3d9\ub0a8\uc544 \uad00\uad11\uacfc \uc548\ubcf4\uc5d0 \ucda9\uaca9\uc744 \uc900\ub2e4.","\ud14c\ub7ec\ub294 \uc5ec\ud589\xb7\ud56d\uacf5 \uc2ec\ub9ac\ub97c \uc704\ucd95\uc2dc\ud0b5\ub2c8\ub2e4. \ub2e8\uae30 \ucda9\uaca9\uacfc \uad6c\uc870\uc801 \uc601\ud5a5\uc744 \uad6c\ubd84\ud558\uc138\uc694.",B.q)
B.VA=new A.l(2002,10,24,"\uce58\uc548","\ubbf8 \uc6cc\uc2f1\ud134 \uc5f0\uc1c4 \uc800\uaca9\ubc94 \uac80\uac70","3\uc8fc\uac04 \uc218\ub3c4\uad8c\uc744 \uacf5\ud3ec\uc5d0 \ube60\ub728\ub9b0 \uc5f0\uc1c4 \uc800\uaca9 \uc6a9\uc758\uc790 \ub450 \uba85\uc774 \ubd99\uc7a1\ud614\ub2e4. \uc5f4 \uba85\uc774 \ubaa9\uc228\uc744 \uc783\uc740 \uc0ac\uac74\uc774 \ub9c8\ubb34\ub9ac\ub410\ub2e4.","\uad6d\uc9c0\uc801 \uc0ac\uac74\ubcf4\ub2e4 \ud070 \ud750\ub984\uc5d0 \uc9d1\uc911\ud558\uc138\uc694. \ub2e8\ubc1c\uc131 \ub274\uc2a4\uc5d0 \ud754\ub4e4\ub9ac\uc9c0 \ub9c8\uc138\uc694.",B.J)
B.a__=new A.l(2002,11,1,"\ubc18\ub3c5\uc810","MS \ubc18\ub3c5\uc810 \uc18c\uc1a1, \ud654\ud574\uc548 \uc0ac\uc2e4\uc0c1 \uc2b9\uc778","\uc5f0\ubc29\ubc95\uc6d0\uc774 \ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8\uc640 \uc815\ubd80\uc758 \ud654\ud574\uc548\uc744 \ub300\uccb4\ub85c \ubc1b\uc544\ub4e4\uc600\ub2e4. \uae30\uc5c5 \ubd84\ud560 \uc704\uae30\ub97c \ubc97\uc5b4\ub0ac\ub2e4.","\uaddc\uc81c \ubd88\ud655\uc2e4\uc131 \ud574\uc18c\ub294 \ub300\ud615 \uae30\uc220\uc8fc\uc5d0 \ud638\uc7ac\uc785\ub2c8\ub2e4. \ud310\uacb0 \ub9ac\uc2a4\ud06c \uc885\ub8cc\ub97c \ud655\uc778\ud558\uc138\uc694.",B.p)
B.ZJ=new A.l(2002,11,15,"\uc628\ub77c\uc778 \uac8c\uc784","MS, \uc5d1\uc2a4\ubc15\uc2a4 \ub77c\uc774\ube0c \uc11c\ube44\uc2a4 \uc2dc\uc791","\ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8\uac00 \ucf58\uc194 \uc628\ub77c\uc778 \uac8c\uc784\ub9dd \uc5d1\uc2a4\ubc15\uc2a4 \ub77c\uc774\ube0c\ub97c \uc120\ubcf4\uc600\ub2e4. \uac8c\uc784\uc774 \ub124\ud2b8\uc6cc\ud06c \uc11c\ube44\uc2a4\ub85c \ud655\uc7a5\ub41c\ub2e4.","\uad6c\ub3c5\ud615 \uc628\ub77c\uc778 \uc11c\ube44\uc2a4\ub294 \ubc18\ubcf5 \ub9e4\ucd9c\uc758 \uc528\uc557\uc785\ub2c8\ub2e4. \uacfc\uae08 \ubaa8\ub378\uc758 \uc131\uc7a5\uc131\uc744 \ubcf4\uc138\uc694.",B.x)
B.Xs=new A.l(2002,12,18,"\ub300\uc120 \ub9c9\ud310","\uc815\ubabd\uc900, \ub178\ubb34\ud604 \ud6c4\ubcf4\uc640 \uacf5\uc870 \ud30c\uae30","\ud22c\ud45c\ub97c \ud558\ub8e8 \uc55e\ub450\uace0 \uc815\ubabd\uc900 \ud6c4\ubcf4\uac00 \ub178\ubb34\ud604 \ud6c4\ubcf4\uc5d0 \ub300\ud55c \uc9c0\uc9c0\ub97c \uc804\uaca9 \ucca0\ud68c\ud588\ub2e4. \ub300\uc120 \ud310\uc138\uac00 \uc694\ub3d9\uce5c\ub2e4.","\uc815\uce58 \uc774\ubca4\ud2b8\uc758 \ubc18\uc804\uc740 \ubcc0\ub3d9\uc131\uc744 \ud0a4\uc6c1\ub2c8\ub2e4. \uacb0\uacfc \ud655\uc815 \uc804\uc5d4 \uad00\ub9dd\uc774 \uc720\ud6a8\ud569\ub2c8\ub2e4.",B.q)
B.Ym=new A.l(2002,12,19,"\ub300\uc120","\uc81c16\ub300 \ub300\uc120, \ub178\ubb34\ud604 \ud6c4\ubcf4 \ub2f9\uc120","\ub178\ubb34\ud604 \ud6c4\ubcf4\uac00 \uc811\uc804 \ub05d\uc5d0 \ub300\ud1b5\ub839\uc5d0 \ub2f9\uc120\ub410\ub2e4. \uac1c\ud601\uacfc \uc138\ub300\uad50\uccb4 \uae30\ub300 \uc18d \uc815\ucc45 \ubcc0\ud654\uac00 \uc608\uace0\ub41c\ub2e4.","\uc815\uad8c \uad50\uccb4\ub294 \uc0b0\uc5c5 \uc815\ucc45 \uc9c0\ud615\uc744 \ubc14\uafc9\ub2c8\ub2e4. \uc218\ud61c\xb7\ud53c\ud574 \uc5c5\uc885\uc744 \ubbf8\ub9ac \uc810\uac80\ud558\uc138\uc694.",B.p)
B.a_w=new A.l(2003,1,7,"\uc560\ud50c \uc2e0\uc81c\ud488","\uc560\ud50c, \uc790\uccb4 \ube0c\ub77c\uc6b0\uc800 '\uc0ac\ud30c\ub9ac' \uacf5\uac1c","\uc560\ud50c\uc774 \ub9e5\uc6d4\ub4dc\uc5d0\uc11c \ub3c5\uc790 \uc6f9\ube0c\ub77c\uc6b0\uc800 \uc0ac\ud30c\ub9ac\ub97c \uc120\ubcf4\uc600\ub2e4. \ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8 \uc758\uc874\uc5d0\uc11c \ubc97\uc5b4\ub098\ub824\ub294 \ud589\ubcf4\ub2e4.","\ud50c\ub7ab\ud3fc \ub0b4\uc7ac\ud654\ub294 \uc0dd\ud0dc\uacc4 \uc7a5\uc545\ub825\uc744 \ud0a4\uc6c1\ub2c8\ub2e4. \uc18c\ud504\ud2b8\uc6e8\uc5b4 \uc804\ub7b5\uc744 \ud568\uaed8 \ubcf4\uc138\uc694.",B.x)
B.ZC=new A.l(2003,1,10,"\ud55c\ubc18\ub3c4 \uc548\ubcf4","\ubd81\ud55c, \ud575\ud655\uc0b0\uae08\uc9c0\uc870\uc57d(NPT) \ud0c8\ud1f4 \uc120\uc5b8","\ubd81\ud55c\uc774 NPT \ud0c8\ud1f4\ub97c \uacf5\uc2dd \uc120\uc5b8\ud588\ub2e4. \uc870\uc57d\uc744 \ud0c8\ud1f4\ud55c \uccab \uc0ac\ub840\ub85c, \ubd81\ud575 \uc704\uae30\uac00 \ub2e4\uc2dc \uace0\uc870\ub41c\ub2e4.","\ubd81\ud575 \ubcc0\uc218\ub294 \ucf54\ub9ac\uc544 \ub514\uc2a4\uce74\uc6b4\ud2b8\uc758 \ud575\uc2ec\uc785\ub2c8\ub2e4. \uae34\uc7a5 \uad6d\uba74\uc758 \ubcc0\ub3d9\uc131\uc5d0 \ub300\ube44\ud558\uc138\uc694.",B.q)
B.a_v=new A.l(2003,1,15,"\uc2e4\uc801","\uc0bc\uc131\uc804\uc790, \uc0ac\uc0c1 \ucd5c\ub300 \uc5f0\uac04 \uc21c\uc774\uc775","\uc0bc\uc131\uc804\uc790\uac00 \uc9c0\ub09c\ud574 \ubc18\ub3c4\uccb4 \ud68c\ubcf5\uc5d0 \ud798\uc785\uc5b4 \uc0ac\uc0c1 \ucd5c\ub300 \uc21c\uc774\uc775\uc744 \ub0c8\ub2e4\uace0 \ubc1d\ud614\ub2e4. \ud55c\uad6d \ub300\ud45c \uae30\uc5c5\uc758 \uc704\uc0c1\uc774 \uad73\uc5b4\uc9c4\ub2e4.","\uc2e4\uc801 \uc2e0\uae30\ub85d\uc740 \ubc18\ub3c4\uccb4 \uc5c5\ud134\uc758 \uc2e0\ud638\uc77c \uc218 \uc788\uc2b5\ub2c8\ub2e4. \uba54\ubaa8\ub9ac \uac00\uaca9 \uc0ac\uc774\ud074\uc744 \ud655\uc778\ud558\uc138\uc694.",B.p)
B.Uo=new A.l(2003,1,25,"\uc778\ud130\ub137 \ub300\ub780","'1\xb725 \uc778\ud130\ub137 \ub300\ub780' \uc804\uad6d \uc778\ud130\ub137 \ub9c8\ube44","\uc2ac\ub798\uba38 \uc6dc\uc774 \ud37c\uc9c0\uba70 \uc804\uad6d\uc758 \uc778\ud130\ub137\uc774 \uba87 \uc2dc\uac04 \ub3d9\uc548 \uba48\ucdc4\ub2e4. \ucd08\uace0\uc18d \uc778\ud130\ub137 \uac15\uad6d\uc758 \ubcf4\uc548 \ud5c8\uc810\uc774 \ub4dc\ub7ec\ub0ac\ub2e4.","\ub514\uc9c0\ud138 \uc778\ud504\ub77c \uc704\ud5d8\uc774 \ubd80\uac01\ub410\uc2b5\ub2c8\ub2e4. \ubcf4\uc548\xb7\ub124\ud2b8\uc6cc\ud06c \uad00\ub828 \uc218\uc694\ub97c \uc0b4\ud53c\uc138\uc694.",B.q)
B.ZQ=new A.l(2003,2,1,"\uc6b0\uc8fc","\uc6b0\uc8fc\uc655\ubcf5\uc120 \uceec\ub7fc\ube44\uc544 \uacf5\uc911\ubd84\ud574","\uadc0\ud658\ud558\ub358 \uc6b0\uc8fc\uc655\ubcf5\uc120 \uceec\ub7fc\ube44\uc544\uac00 \ub300\uae30\uad8c\uc5d0\uc11c \uacf5\uc911\ubd84\ud574\ub3fc \uc2b9\ubb34\uc6d0 7\uba85 \uc804\uc6d0\uc774 \uc228\uc84c\ub2e4. \ubbf8\uad6d \uc6b0\uc8fc\uacc4\ud68d\uc774 \uba48\ucdb0\uc120\ub2e4.","\ub300\ud615 \uc0ac\uace0\ub294 \uad00\ub828 \uc608\uc0b0\uacfc \uc0b0\uc5c5 \uc77c\uc815\uc744 \ubc14\uafc9\ub2c8\ub2e4. \ud56d\uacf5\uc6b0\uc8fc \uc815\ucc45 \ubc29\ud5a5\uc744 \uc9c0\ucf1c\ubcf4\uc138\uc694.",B.q)
B.Yl=new A.l(2003,2,3,"\ucd08\uace0\uc18d \uc778\ud130\ub137","\uc18c\ud504\ud2b8\ubc45\ud06c '\uc57c\ud6c4! BB' \uac00\uc785 200\ub9cc \ub3cc\ud30c","\uc190\uc815\uc758\uc758 \uc57c\ud6c4! BB\uac00 \uacf5\uaca9\uc801 \ub9c8\ucf00\ud305\uc73c\ub85c \uc77c\ubcf8 \ucd08\uace0\uc18d \uc778\ud130\ub137 \uac00\uc785\uc790 200\ub9cc \uba85\uc744 \ub118\uc5c8\ub2e4. \ud1b5\uc2e0\uc2dc\uc7a5 \ud310\uc744 \ud754\ub4e0\ub2e4.","\ud30c\uad34\uc801 \uc800\uac00 \uc804\ub7b5\uc740 \uc810\uc720\uc728\uc744 \ud0a4\uc6b0\ub418 \uc218\uc775\uc131\uc744 \uc555\ubc15\ud569\ub2c8\ub2e4. \ud604\uae08\ud750\ub984\uc744 \ud655\uc778\ud558\uc138\uc694.",B.p)
B.a_q=new A.l(2003,2,18,"\ub300\ud615 \ucc38\uc0ac","\ub300\uad6c \uc9c0\ud558\ucca0 \ud654\uc7ac \ucc38\uc0ac \ubc1c\uc0dd","\ubc29\ud654\ub85c \uc2dc\uc791\ub41c \ub300\uad6c \uc9c0\ud558\ucca0 \ud654\uc7ac\ub85c 192\uba85\uc774 \uc228\uc9c0\ub294 \ub300\ud615 \ucc38\uc0ac\uac00 \ub0ac\ub2e4. \ub3c4\uc2dc \uc548\uc804 \uc2dc\uc2a4\ud15c \uc804\ubc18\uc774 \ub3c4\ub9c8\uc5d0 \uc624\ub978\ub2e4.","\ucc38\uc0ac\ub294 \uc548\uc804 \uaddc\uc81c \uac15\ud654\ub85c \uc774\uc5b4\uc9d1\ub2c8\ub2e4. \ubc29\uc7ac\xb7\uc2dc\uc124 \ud22c\uc790 \uc218\uc694\ub97c \uc810\uac80\ud558\uc138\uc694.",B.q)
B.XP=new A.l(2003,2,25,"\uc0c8 \uc815\ubd80","\ub178\ubb34\ud604 \uc81c16\ub300 \ub300\ud1b5\ub839 \ucde8\uc784","\ub178\ubb34\ud604 \ub300\ud1b5\ub839\uc774 \ucc38\uc5ec\uc815\ubd80\uc758 \ucd9c\ubc94\uc744 \uc54c\ub9ac\uba70 \ucde8\uc784\ud588\ub2e4. \uac1c\ud601\uacfc \ubd84\uad8c\uc744 \uc55e\uc138\uc6b4 \uad6d\uc815 \ubc29\ud5a5\uc774 \uc81c\uc2dc\ub41c\ub2e4.","\uc0c8 \uc815\ubd80\uc758 \uc815\ucc45 \uc6b0\uc120\uc21c\uc704\uac00 \uace7 \ud14c\ub9c8\uc785\ub2c8\ub2e4. \uc7ac\ubc8c\xb7\ubd80\ub3d9\uc0b0\xb7\ubcf5\uc9c0 \uc815\ucc45\uc744 \uc8fc\uc2dc\ud558\uc138\uc694.",B.p)
B.Wp=new A.l(2003,3,12,"\uc2e0\uc885 \uac10\uc5fc\ubcd1","WHO, \uc0ac\uc2a4(SARS) \uc138\uacc4 \uacbd\ubcf4 \ubc1c\ub839","\uc138\uacc4\ubcf4\uac74\uae30\uad6c\uac00 \uc6d0\uc778 \ubd88\uba85 \ud3d0\ub834 \uc0ac\uc2a4\uc5d0 \ub300\ud574 \uc804 \uc138\uacc4 \uacbd\ubcf4\ub97c \ub0c8\ub2e4. \uc544\uc2dc\uc544\ub97c \uc911\uc2ec\uc73c\ub85c \uac10\uc5fc \uacf5\ud3ec\uac00 \ubc88\uc9c4\ub2e4.","\uac10\uc5fc\ubcd1\uc740 \uc5ec\ud589\xb7\uc18c\ube44\ub97c \uc704\ucd95\uc2dc\ud0a4\ub418 \uc9c4\ub2e8\xb7\ubc29\uc5ed \uc218\uc694\ub97c \ub9cc\ub4ed\ub2c8\ub2e4. \uc5c5\uc885\ubcc4\ub85c \ub098\ub220 \ubcf4\uc138\uc694.",B.q)
B.VE=new A.l(2003,3,15,"\uc911\uad6d \uad8c\ub825\uad50\uccb4","\ud6c4\uc9c4\ud0c0\uc624, \uc911\uad6d \uad6d\uac00\uc8fc\uc11d \ucde8\uc784","\ud6c4\uc9c4\ud0c0\uc624\uac00 \uc804\uad6d\uc778\ubbfc\ub300\ud45c\ub300\ud68c\uc5d0\uc11c \uad6d\uac00\uc8fc\uc11d\uc5d0 \uc120\ucd9c\ub410\ub2e4. \uc138\uacc4\uc758 \uacf5\uc7a5 \uc911\uad6d\uc758 \uc0c8 \uc9c0\ub3c4\ubd80\uac00 \ucd9c\ubc94\ud55c\ub2e4.","\uc911\uad6d \ub9ac\ub354\uc2ed \uad50\uccb4\ub294 \uc131\uc7a5\xb7\uc790\uc6d0 \uc815\ucc45\uc5d0 \uc601\ud5a5\uc744 \uc90d\ub2c8\ub2e4. \ub300\uc911\uad6d \uc218\ucd9c\uc8fc\ub97c \uc0b4\ud53c\uc138\uc694.",B.p)
B.Zm=new A.l(2003,3,20,"\uc804\uc7c1 \uac1c\uc804","\ubbf8\uad6d \uc8fc\ub3c4 \uc5f0\ud569\uad70, \uc774\ub77c\ud06c \uce68\uacf5 \uac1c\uc2dc","\ubbf8\uad6d\xb7\uc601\uad6d \uc8fc\ub3c4 \uc5f0\ud569\uad70\uc774 \uc774\ub77c\ud06c \uacf5\uaca9\uc744 \uc2dc\uc791\ud588\ub2e4. \uc720\uac00\uc640 \uc548\uc804\uc790\uc0b0\uc774 \uc694\ub3d9\uce58\uba70 \uc804\uc7c1 \uad6d\uba74\uc5d0 \ub4e4\uc5b4\uac04\ub2e4.","\uc804\uc7c1\uc740 \uc720\uac00\uc640 \uc704\ud5d8\uc120\ud638\ub97c \ub4a4\ud754\ub4ed\ub2c8\ub2e4. \uc5d0\ub108\uc9c0 \ub178\ucd9c\uacfc \ubc29\uc5b4\uc790\uc0b0\uc744 \ud568\uaed8 \uc810\uac80\ud558\uc138\uc694.",B.q)
B.Yj=new A.l(2003,3,20,"\uc778\uc218\ud569\ubcd1","\uc2dc\uc2a4\ucf54, \uac00\uc815\uc6a9 \ub124\ud2b8\uc6cc\ud06c \ub9c1\ud06c\uc2dc\uc2a4 \uc778\uc218","\uc2dc\uc2a4\ucf54\uac00 \ud648 \ub124\ud2b8\uc6cc\ud0b9 \uae30\uc5c5 \ub9c1\ud06c\uc2dc\uc2a4\ub97c \uc778\uc218\ud558\uae30\ub85c \ud588\ub2e4. \uae30\uc5c5\uc6a9\uc744 \ub118\uc5b4 \uc18c\ube44\uc790 \uc2dc\uc7a5\uc73c\ub85c \ubc1c\uc744 \ub113\ud78c\ub2e4.","\uc2e0\uc2dc\uc7a5 \uc9c4\ucd9c \uc778\uc218\ub294 \uc131\uc7a5 \ub3d9\ub825\uc744 \ub113\ud799\ub2c8\ub2e4. \ud1b5\ud569 \ud6a8\uacfc\uc640 \ub9c8\uc9c4 \ubcc0\ud654\ub97c \uc9c0\ucf1c\ubcf4\uc138\uc694.",B.p)
B.Xd=new A.l(2003,4,9,"\ubc14\uadf8\ub2e4\ub4dc \ud568\ub77d","\ubc14\uadf8\ub2e4\ub4dc \ud568\ub77d, \ud6c4\uc138\uc778 \ub3d9\uc0c1 \ubb34\ub108\uc9c0\ub2e4","\uc5f0\ud569\uad70\uc774 \ubc14\uadf8\ub2e4\ub4dc\ub97c \uc7a5\uc545\ud558\uace0 \ud6c4\uc138\uc778 \ub3d9\uc0c1\uc774 \uad11\uc7a5\uc5d0\uc11c \ub04c\uc5b4\ub0b4\ub824\uc84c\ub2e4. \uadf8\ub7ec\ub098 \uc804\uc7c1\uc740 \uc544\uc9c1 \ub05d\ub098\uc9c0 \uc54a\uc558\ub2e4.","'\uc2b9\ub9ac' \ub274\uc2a4\uac00 \uace7 \uc548\uc815\uc740 \uc544\ub2d9\ub2c8\ub2e4. \uc885\uc804 \uc774\ud6c4\uc758 \ubd88\ud655\uc2e4\uc131\uc744 \ud568\uaed8 \uacc4\uc0b0\ud558\uc138\uc694.",B.q)
B.U8=new A.l(2003,4,14,"\uacfc\ud559 \ud601\uc2e0","\uc778\uac04\uac8c\ub188\uc9c0\ub3c4 \uc0ac\uc2e4\uc0c1 \uc644\uc131 \ubc1c\ud45c","\uad6d\uc81c \ucee8\uc18c\uc2dc\uc5c4\uc774 \uc778\uac04\uac8c\ub188 \ud574\ub3c5\uc744 \uc0ac\uc2e4\uc0c1 \uc644\ub8cc\ud588\ub2e4\uace0 \ubc1c\ud45c\ud588\ub2e4. \uc0dd\uba85\uacf5\ud559\uacfc \uc2e0\uc57d \uac1c\ubc1c\uc758 \uc0c8 \uc7a5\uc774 \uc5f4\ub9b0\ub2e4.","\uae30\ucd08\uacfc\ud559\uc758 \ub3c4\uc57d\uc740 \uc7a5\uae30 \uc131\uc7a5 \ud14c\ub9c8\uc785\ub2c8\ub2e4. \ubc14\uc774\uc624 \uae30\ub300\ub294 \uc2e4\ud604 \uc2dc\uc810\uc744 \ub0c9\uc815\ud788 \ubcf4\uc138\uc694.",B.p)
B.Ud=new A.l(2003,4,24,"\uc18c\ub2c8 \uc1fc\ud06c","'\uc18c\ub2c8 \uc1fc\ud06c', \uc2e4\uc801 \uacbd\uace0\uc5d0 \uc8fc\uac00 \uae09\ub77d","\uc18c\ub2c8\uac00 \uc2e4\uc801 \uc804\ub9dd\uc744 \ub300\ud3ed \ub0ae\ucd94\uc790 \uc8fc\uac00\uac00 \uae09\ub77d\ud558\uba70 \ub2db\ucf00\uc774 \uc804\uccb4\ub97c \ub04c\uc5b4\ub0b4\ub838\ub2e4. \uc77c\ubcf8 \ub300\ud45c \uc804\uc790\uae30\uc5c5\uc758 \ubd80\uc9c4\uc774 \ub4dc\ub7ec\ub09c\ub2e4.","\uac04\ud310 \uae30\uc5c5\uc758 \uc2e4\uc801 \uc1fc\ud06c\ub294 \uc9c0\uc218 \uc804\ubc18\uc744 \ud754\ub4ed\ub2c8\ub2e4. \uc2e4\uc801 \uac00\uc2dc\uc131\uc774 \ub0ae\uc744 \ub550 \ubab8\uc744 \ub0ae\ucd94\uc138\uc694.",B.q)
B.Xa=new A.l(2003,4,24,"\uae30\uc5c5 IT","MS, \uc708\ub3c4 \uc11c\ubc84 2003 \uc815\uc2dd \ucd9c\uc2dc","\ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8\uac00 \uae30\uc5c5\uc6a9 \uc6b4\uc601\uccb4\uc81c \uc708\ub3c4 \uc11c\ubc84 2003\uc744 \uc804 \uc138\uacc4\uc5d0 \ub0b4\ub1a8\ub2e4. \uae30\uc5c5 IT \uc778\ud504\ub77c \uad50\uccb4 \uc218\uc694\ub97c \uaca8\ub0e5\ud55c\ub2e4.","\uae30\uc5c5 IT \ud22c\uc790 \uc7ac\uac1c\ub294 \ud558\ub4dc\xb7\uc18c\ud504\ud2b8 \uc218\uc694\ub97c \ud568\uaed8 \uc790\uadf9\ud569\ub2c8\ub2e4. \uad00\ub828 \ubc38\ub958\uccb4\uc778\uc744 \ubcf4\uc138\uc694.",B.x)
B.Ue=new A.l(2003,4,28,"\ub514\uc9c0\ud138 \uc74c\uc545","\uc560\ud50c, \uc544\uc774\ud2a0\uc988 \ubba4\uc9c1\uc2a4\ud1a0\uc5b4 \uac1c\uc7a5","\uc560\ud50c\uc774 \uace1\ub2f9 \uacb0\uc81c \ubc29\uc2dd\uc758 \uc544\uc774\ud2a0\uc988 \ubba4\uc9c1\uc2a4\ud1a0\uc5b4\ub97c \uc5f4\uc5c8\ub2e4. \uccab \uc8fc 100\ub9cc \uace1\uc774 \ud314\ub9ac\uba70 \uc74c\uc545 \uc720\ud1b5\uc744 \ubc14\uafd4\ub193\ub294\ub2e4.","\ud569\ubc95 \ub2e4\uc6b4\ub85c\ub4dc \ubaa8\ub378\uc758 \ub4f1\uc7a5\uc785\ub2c8\ub2e4. \ucf58\ud150\uce20 \uc720\ud1b5 \uad6c\uc870\uc758 \ubcc0\ud654\ub97c \uc7a5\uae30\ub85c \uc9c0\ucf1c\ubcf4\uc138\uc694.",B.x)
B.Z_=new A.l(2003,5,1,"\uc774\ub77c\ud06c\uc804","\ubd80\uc2dc, \uc774\ub77c\ud06c '\uc8fc\uc694 \uc804\ud22c \uc885\ub8cc' \uc120\uc5b8","\ubd80\uc2dc \ub300\ud1b5\ub839\uc774 \ud56d\uacf5\ubaa8\ud568\uc5d0\uc11c \uc8fc\uc694 \uc804\ud22c \uc791\uc804\uc758 \uc885\ub8cc\ub97c \uc120\uc5b8\ud588\ub2e4. \uadf8\ub7ec\ub098 \ud604\uc9c0 \uc815\uc138\ub294 \uc5ec\uc804\ud788 \ubd88\uc548\ud558\ub2e4.","\ub099\uad00 \uc120\uc5b8\uacfc \uc2e4\uc81c \uc548\uc815\uc740 \ub2e4\ub985\ub2c8\ub2e4. \uc720\uac00\xb7\uc9c0\uc815\ud559 \ubcc0\uc218\uc758 \uc9c0\uc18d\uc131\uc5d0 \uc720\uc758\ud558\uc138\uc694.",B.J)
B.Yg=new A.l(2003,5,9,"\uc2e4\uc801","\ud1a0\uc694\ud0c0, \u65e5 \uae30\uc5c5 \uccab \uc21c\uc774\uc775 1\uc870 \uc5d4","\ud1a0\uc694\ud0c0\uac00 \uc77c\ubcf8 \uae30\uc5c5 \ucd5c\ucd08\ub85c \uc5f0\uac04 \uc21c\uc774\uc775 1\uc870 \uc5d4\uc744 \ub118\uacbc\ub2e4\uace0 \ubc1c\ud45c\ud588\ub2e4. \uae00\ub85c\ubc8c \uc644\uc131\ucc28 \uac15\uc790\uc758 \ud798\uc744 \ubcf4\uc5ec\uc900\ub2e4.","\uc218\ucd9c \ub300\uae30\uc5c5\uc758 \uae30\ub85d \uc2e4\uc801\uc5d4 \ud658\uc728 \ud6a8\uacfc\uac00 \ud07d\ub2c8\ub2e4. \uc5d4\ud654 \ubc29\ud5a5\uc744 \ud568\uaed8 \ud655\uc778\ud558\uc138\uc694.",B.p)
B.Yk=new A.l(2003,6,23,"\uc560\ud50c \uc2e0\uc81c\ud488","\uc560\ud50c, 64\ube44\ud2b8 \ud30c\uc6cc\ub9e5 G5 \uacf5\uac1c","\uc560\ud50c\uc774 \uc138\uacc4 \ucd5c\ucd08\ub97c \ud45c\ubc29\ud55c 64\ube44\ud2b8 \ub370\uc2a4\ud06c\ud1b1 \ud30c\uc6cc\ub9e5 G5\ub97c \uc120\ubcf4\uc600\ub2e4. \uace0\uc131\ub2a5 \ucef4\ud4e8\ud305 \uacbd\uc7c1\uc774 \ub2ec\uc544\uc624\ub978\ub2e4.","\uace0\uc131\ub2a5 \uc804\ud658\uc740 \ud504\ub85c\uc138\uc11c \uacbd\uc7c1\uc744 \uac00\uc18d\ud569\ub2c8\ub2e4. \ubc18\ub3c4\uccb4 \ub85c\ub4dc\ub9f5\uc758 \uc2b9\uc790\ub97c \uc0b4\ud53c\uc138\uc694.",B.x)
B.Yq=new A.l(2003,7,5,"\ubc29\uc5ed \uc131\uacfc","WHO, \uc0ac\uc2a4 \uc138\uacc4\uc801 \ud655\uc0b0 \uc885\uc2dd \uc120\uc5b8","\uc138\uacc4\ubcf4\uac74\uae30\uad6c\uac00 \uc0ac\uc2a4\uc758 \uc138\uacc4\uc801 \ud655\uc0b0\uc774 \uc5b5\uc81c\ub410\ub2e4\uace0 \ubc1d\ud614\ub2e4. \ub109 \ub2ec \ub118\uac8c \uc774\uc5b4\uc9c4 \uac10\uc5fc \uacf5\ud3ec\uac00 \uc9c4\uc815\ub41c\ub2e4.","\uc704\uae30 \uc9c4\uc815 \uad6d\uba74\uc5d4 \uc5ec\ud589\xb7\uc18c\ube44 \ud68c\ubcf5\uc774 \uc2dc\uc791\ub429\ub2c8\ub2e4. \ub099\ud3ed \uacfc\ub300 \uc5c5\uc885\uc744 \uc810\uac80\ud558\uc138\uc694.",B.J)
B.a_B=new A.l(2003,7,22,"\uc774\ub77c\ud06c","\ud6c4\uc138\uc778\uc758 \ub450 \uc544\ub4e4, \ubaa8\uc220\uc11c \uc0ac\uc0b4","\ubbf8\uad70 \uc791\uc804\uc73c\ub85c \uc0ac\ub2f4 \ud6c4\uc138\uc778\uc758 \ub450 \uc544\ub4e4\uc774 \uc774\ub77c\ud06c \ubaa8\uc220\uc5d0\uc11c \uc0ac\uc0b4\ub410\ub2e4. \uad6c\uc815\uad8c \uc794\uc874 \uc138\ub825\uc5d0 \ud0c0\uaca9\uc774 \uac00\ud574\uc9c4\ub2e4.","\uad6d\uc9c0\uc801 \uc131\uacfc\uac00 \uace7 \uc548\uc815\uc740 \uc544\ub2d9\ub2c8\ub2e4. \uc774\ub77c\ud06c \uc815\uc138\uc758 \uc7a5\uae30 \ub9ac\uc2a4\ud06c\ub97c \uacc4\uc18d \ubc18\uc601\ud558\uc138\uc694.",B.q)
B.Ua=new A.l(2003,8,4,"\uc7ac\uacc4 \ube44\ubcf4","\ud604\ub300\uc544\uc0b0 \uc815\ubabd\ud5cc \ud68c\uc7a5 \ubcc4\uc138","\ud604\ub300\uadf8\ub8f9\uc758 \ub300\ubd81\uc0ac\uc5c5\uc744 \uc774\ub04c\ub358 \uc815\ubabd\ud5cc \ud68c\uc7a5\uc774 \uc138\uc0c1\uc744 \ub5a0\ub0ac\ub2e4. \ub300\ubd81\uc1a1\uae08 \uad00\ub828 \uc218\uc0ac\uac00 \uc9c4\ud589\ub418\ub358 \uc911\uc774\uc5c8\ub2e4.","\ucd1d\uc218 \ub9ac\uc2a4\ud06c\ub294 \uadf8\ub8f9 \uacc4\uc5f4\uc0ac \uc804\ubc18\uc5d0 \ud30c\uc7a5\uc744 \uc90d\ub2c8\ub2e4. \uc9c0\ubc30\uad6c\uc870 \uc548\uc815\uc131\uc744 \uc810\uac80\ud558\uc138\uc694.",B.q)
B.a_z=new A.l(2003,8,14,"\ub300\uc815\uc804","\ubbf8\uad6d \ubd81\ub3d9\ubd80\xb7\uce90\ub098\ub2e4 \uc0ac\uc0c1 \ucd5c\uc545 \uc815\uc804","\ubd81\ub3d9\ubd80 \ubbf8\uad6d\uacfc \uce90\ub098\ub2e4\uc5d0\uc11c \uc57d 5\ucc9c\ub9cc \uba85\uc774 \uc815\uc804\uc744 \uacaa\ub294 \ucd5c\uc545\uc758 \ube14\ub799\uc544\uc6c3\uc774 \ubc1c\uc0dd\ud588\ub2e4. \ub178\ud6c4 \uc804\ub825\ub9dd\uc758 \ucde8\uc57d\uc131\uc774 \ub4dc\ub7ec\ub09c\ub2e4.","\uc778\ud504\ub77c \ub178\ud6c4\ub294 \ub300\uaddc\ubaa8 \ud22c\uc790 \uc218\uc694\ub97c \uc608\uace0\ud569\ub2c8\ub2e4. \uc804\ub825\xb7\uc124\ube44 \uad00\ub828 \ud750\ub984\uc744 \uc0b4\ud53c\uc138\uc694.",B.q)
B.W7=new A.l(2003,8,29,"\uc81c\ub3c4 \ubcc0\ud654","\uad6d\ud68c, \uc8fc5\uc77c \uadfc\ubb34\uc81c \ubc95\uc548 \ud1b5\uacfc","\uc8fc5\uc77c \uadfc\ubb34\uc81c\ub97c \ub2f4\uc740 \uadfc\ub85c\uae30\uc900\ubc95 \uac1c\uc815\uc548\uc774 \uad6d\ud68c\ub97c \ud1b5\uacfc\ud588\ub2e4. \uc5ec\uac00\xb7\uc18c\ube44 \ubb38\ud654\uc758 \ubcc0\ud654\uac00 \uc608\uace0\ub41c\ub2e4.","\uadfc\ub85c\uc2dc\uac04 \ub2e8\ucd95\uc740 \ub808\uc800\xb7\uc18c\ube44 \uc9c0\ud615\uc744 \ubc14\uafc9\ub2c8\ub2e4. \uc5ec\uac00\xb7\uc720\ud1b5 \uc218\ud61c\uc8fc\ub97c \ubbf8\ub9ac \ubcf4\uc138\uc694.",B.p)
B.XE=new A.l(2003,9,12,"\uc790\uc5f0\uc7ac\ud574","\ud0dc\ud48d '\ub9e4\ubbf8', \ub0a8\ubd80 \uc9c0\ubc29 \uac15\ud0c0","\uad00\uce21 \uc0ac\uc0c1 \ucd5c\uac15\uae09 \ud0dc\ud48d \ub9e4\ubbf8\uac00 \ubd80\uc0b0\xb7\uacbd\ub0a8\uc744 \uac15\ud0c0\ud574 \ud070 \uc778\uba85\xb7\uc7ac\uc0b0 \ud53c\ud574\ub97c \ub0c8\ub2e4. \ud56d\ub9cc\uacfc \ub18d\uc791\ubb3c \ud53c\ud574\uac00 \ud2b9\ud788 \ud06c\ub2e4.","\uac15\ub825 \uc7ac\ud574\ub294 \ubb3c\ub958\xb7\ubb3c\uac00\uc5d0 \ubd80\ub2f4\uc744 \uc90d\ub2c8\ub2e4. \ubcf5\uad6c \uc218\uc694\uc640 \uc190\ud574 \uc5c5\uc885\uc744 \ub098\ub220 \ubcf4\uc138\uc694.",B.q)
B.Uk=new A.l(2003,10,7,"\ubbf8\uad6d \uc815\uce58","\uc288\uc6cc\uc81c\ub124\uac70, \uce98\ub9ac\ud3ec\ub2c8\uc544 \uc8fc\uc9c0\uc0ac \ub2f9\uc120","\uc8fc\ubbfc\uc18c\ud658 \ud22c\ud45c\ub85c \ub370\uc774\ube44\uc2a4 \uc8fc\uc9c0\uc0ac\uac00 \ubb3c\ub7ec\ub098\uace0 \ubc30\uc6b0 \ucd9c\uc2e0 \uc288\uc6cc\uc81c\ub124\uac70\uac00 \ub2f9\uc120\ub410\ub2e4. \uc774\ub840\uc801 \uc815\uce58 \uc774\ubca4\ud2b8\uac00 \ud654\uc81c\ub97c \ubaa8\uc740\ub2e4.","\uc815\uce58 \uc774\ubca4\ud2b8\ub294 \ud654\uc81c\uc640 \uc2e4\uc9c8\uc744 \uad6c\ubd84\ud574\uc57c \ud569\ub2c8\ub2e4. \uc9c0\uc5ed \uc7ac\uc815\xb7\uc815\ucc45 \ubcc0\ud654\uc5d0 \uc8fc\ubaa9\ud558\uc138\uc694.",B.p)
B.Xb=new A.l(2003,10,15,"\uc6b0\uc8fc \uacbd\uc7c1","\uc911\uad6d, \uccab \uc720\uc778\uc6b0\uc8fc\uc120 \uc120\uc800\uc6b0 5\ud638 \ubc1c\uc0ac","\uc911\uad6d\uc774 \uc591\ub9ac\uc6e8\uc774\ub97c \ud0dc\uc6b4 \uc120\uc800\uc6b0 5\ud638\ub97c \uc3d8\uc544\uc62c\ub824 \uc138 \ubc88\uc9f8 \uc720\uc778\uc6b0\uc8fc \ube44\ud589\uad6d\uc774 \ub410\ub2e4. \uae30\uc220 \uad74\uae30\ub97c \uc138\uacc4\uc5d0 \uacfc\uc2dc\ud55c\ub2e4.","\uad6d\uac00 \uc8fc\ub3c4 \uae30\uc220 \uad74\uae30\ub294 \uad00\ub828 \uc0b0\uc5c5\uc744 \ud0a4\uc6c1\ub2c8\ub2e4. \ud56d\uacf5\uc6b0\uc8fc\xb7\uc18c\uc7ac \ubc38\ub958\uccb4\uc778\uc744 \uc0b4\ud53c\uc138\uc694.",B.p)
B.XC=new A.l(2003,10,16,"\ub514\uc9c0\ud138 \uc74c\uc545","\uc560\ud50c, \uc708\ub3c4\uc6a9 \uc544\uc774\ud2a0\uc988 \ucd9c\uc2dc","\uc560\ud50c\uc774 \uc544\uc774\ud2a0\uc988\ub97c \uc708\ub3c4 \uc0ac\uc6a9\uc790\uc5d0\uac8c\ub3c4 \uac1c\ubc29\ud588\ub2e4. \uc544\uc774\ud31f\uacfc \uc74c\uc545 \ud310\ub9e4\uc758 \uc2dc\uc7a5\uc774 \ub2e8\uc228\uc5d0 \ub113\uc5b4\uc9c4\ub2e4.","\ud50c\ub7ab\ud3fc \uac1c\ubc29\uc740 \uc0ac\uc6a9\uc790 \uc800\ubcc0\uc744 \ub113\ud799\ub2c8\ub2e4. \ud558\ub4dc\uc6e8\uc5b4\xb7\uc11c\ube44\uc2a4 \ub3d9\ubc18 \uc131\uc7a5\uc744 \uc9c0\ucf1c\ubcf4\uc138\uc694.",B.x)
B.ZG=new A.l(2003,10,24,"\ud55c \uc2dc\ub300\uc758 \ub05d","\ucd08\uc74c\uc18d \uc5ec\uac1d\uae30 \ucf69\ucf54\ub4dc, \ub9c8\uc9c0\ub9c9 \ube44\ud589","27\ub144\uac04 \ud558\ub298\uc744 \uac00\ub978 \ucd08\uc74c\uc18d \uc5ec\uac1d\uae30 \ucf69\ucf54\ub4dc\uac00 \ub9c8\uc9c0\ub9c9 \uc0c1\uc5c5 \ube44\ud589\uc744 \ub9c8\ucce4\ub2e4. \ud654\ub824\ud588\ub358 \ucd08\uc74c\uc18d \uc2dc\ub300\uac00 \uc800\ubb38\ub2e4.","\uae30\uc220 \uc6b0\uc704\ub3c4 \uc218\uc775\uc131\uc774 \uc5c6\uc73c\uba74 \uc0ac\ub77c\uc9d1\ub2c8\ub2e4. \ube44\uc6a9 \uad6c\uc870\uac00 \ub2f4\ubcf4\ub418\uc9c0 \uc54a\uc740 \ud601\uc2e0\uc744 \uacbd\uacc4\ud558\uc138\uc694.",B.p)
B.W9=new A.l(2003,11,11,"\uc815\uacc4 \uac1c\ud3b8","\uc5f4\ub9b0\uc6b0\ub9ac\ub2f9 \ucc3d\ub2f9","\ub178\ubb34\ud604 \ub300\ud1b5\ub839 \uc9c0\uc9c0 \uc138\ub825\uc774 \uc8fc\ucd95\uc774 \ub41c \uc5f4\ub9b0\uc6b0\ub9ac\ub2f9\uc774 \ucc3d\ub2f9\ud588\ub2e4. \uc774\ub4ec\ud574 \ucd1d\uc120\uc744 \uc55e\ub450\uace0 \uc815\uacc4 \uac1c\ud3b8\uc774 \ubcf8\uaca9\ud654\ud55c\ub2e4.","\uc815\uacc4 \uc7ac\ud3b8\uc740 \uc815\ucc45 \uc6b0\uc120\uc21c\uc704\ub97c \ubc14\uafc9\ub2c8\ub2e4. \ucd1d\uc120 \uad6d\uba74\uc758 \uc815\ucc45 \ud14c\ub9c8\ub97c \ubbf8\ub9ac \uc810\uac80\ud558\uc138\uc694.",B.p)
B.YV=new A.l(2003,11,24,"\uc2e0\uc6a9\ub300\ub780","LG\uce74\ub4dc, \ucc44\uad8c\ub2e8 \uae34\uae09 \uc790\uae08 \uc9c0\uc6d0","\uc720\ub3d9\uc131 \uc704\uae30\uc5d0 \ubab0\ub9b0 LG\uce74\ub4dc\uac00 \ucc44\uad8c\ub2e8\uc758 \uae34\uae09 \uc9c0\uc6d0\uc744 \ubc1b\uc558\ub2e4. \ubb34\ubd84\ubcc4\ud55c \uce74\ub4dc \ubc1c\uae09\uc774 \ubd80\ub978 \uc2e0\uc6a9\ub300\ub780\uc774 \uc815\uc810\uc5d0 \uc774\ub978\ub2e4.","\uac00\uacc4 \uc2e0\uc6a9 \uc704\uae30\ub294 \uae08\uc735\uc8fc \uc804\ubc18\uc758 \uc704\ud5d8\uc785\ub2c8\ub2e4. \uc5f0\uccb4\uc728\uacfc \uc790\ubcf8 \uac74\uc804\uc131\uc744 \ud655\uc778\ud558\uc138\uc694.",B.q)
B.WS=new A.l(2003,12,13,"\uc774\ub77c\ud06c","\uc0ac\ub2f4 \ud6c4\uc138\uc778, \uace0\ud5a5 \uc778\uadfc\uc11c \uccb4\ud3ec","\ubbf8\uad70\uc774 \uc0ac\ub2f4 \ud6c4\uc138\uc778\uc744 \ud2f0\ud06c\ub9ac\ud2b8 \uc778\uadfc \uc740\uc2e0\ucc98\uc5d0\uc11c \ubd99\uc7a1\uc558\ub2e4. \uc774\ub77c\ud06c\uc804\uc758 \uc0c1\uc9d5\uc801 \uad6d\uba74\uc774 \ub9c8\ubb34\ub9ac\ub41c\ub2e4.","\uc0c1\uc9d5\uc801 \uc0ac\uac74\uc740 \ub2e8\uae30 \uc548\ub3c4\ub7a0\ub9ac\ub97c \ubd80\ub974\uace4 \ud569\ub2c8\ub2e4. \uc774\ud6c4\uc758 \ud604\uc2e4 \uc9c0\ud45c\ub85c \ud310\ub2e8\ud558\uc138\uc694.",B.p)
B.Yc=new A.l(2003,12,26,"\uc790\uc5f0\uc7ac\ud574","\uc774\ub780 \ubc24 \uc9c0\uc9c4, \uace0\ub300\ub3c4\uc2dc \ucd08\ud1a0\ud654","\uc774\ub780 \ub0a8\ub3d9\ubd80 \ubc24\uc5d0\uc11c \uac15\uc9c4\uc774 \ub098 \uc218\ub9cc \uba85\uc774 \uc228\uc9c0\uace0 \uc138\uacc4\ubb38\ud654\uc720\uc0b0 \ub3c4\uc2dc\uac00 \ubb34\ub108\uc84c\ub2e4. \uad6d\uc81c \uad6c\ud638\uc758 \uc190\uae38\uc774 \uc774\uc5b4\uc9c4\ub2e4.","\ub300\uc7ac\ud574\ub294 \uc778\ub3c4\uc801 \uc704\uae30\uc774\uc790 \uc6d0\uc790\uc7ac\xb7\uc7ac\uac74 \ubcc0\uc218\uc785\ub2c8\ub2e4. \uc0ac\uc2e4\uc744 \uba3c\uc800 \ud655\uc778\ud558\uc138\uc694.",B.q)
B.WI=new A.l(2004,1,4,"\uc6b0\uc8fc","NASA \ud654\uc131\ud0d0\uc0ac \ub85c\ubc84 \uc2a4\ud53c\ub9bf \ucc29\ub959 \uc131\uacf5","\ubbf8 \ud56d\uacf5\uc6b0\uc8fc\uad6d\uc758 \ud0d0\uc0ac \ub85c\ubc84 \uc2a4\ud53c\ub9bf\uc774 \ud654\uc131 \ud45c\uba74\uc5d0 \ubb34\uc0ac\ud788 \ub0b4\ub824\uc549\uc558\ub2e4.","\uc6b0\uc8fc\xb7\ucca8\ub2e8\uae30\uc220 \ud14c\ub9c8\uac00 \ub300\uc911\uc758 \uad00\uc2ec\uad8c\uc73c\ub85c \ub4e4\uc5b4\uc635\ub2c8\ub2e4.",B.p)
B.a_5=new A.l(2004,1,6,"\uc2e0\uc81c\ud488","\uc560\ud50c, \ucd08\uc18c\ud615 \uc544\uc774\ud31f \ubbf8\ub2c8 \uacf5\uac1c","\uc560\ud50c\uc774 \ub9e5\uc6d4\ub4dc\uc5d0\uc11c \ub2e4\uc12f \uac00\uc9c0 \uc0c9\uc0c1\uc758 \uc18c\ud615 MP3 \ud50c\ub808\uc774\uc5b4 \uc544\uc774\ud31f \ubbf8\ub2c8\ub97c \uc120\ubcf4\uc600\ub2e4.","\ud734\ub300\uc6a9 \uae30\uae30 \uc2dc\uc7a5\uc758 \ud655\uc7a5 \ud750\ub984\uc744 \uc9c0\ucf1c\ubcfc \ub9cc\ud569\ub2c8\ub2e4.",B.x)
